}

"use client"

import { useState, useEffect, useMemo } from "react";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Users, CreditCard, Building2, UserCog, DollarSign } from "lucide-react";
import { AllUsersTab } from "@/components/dashboard/people/users/AllUsersTab";
import { RolesTab } from "@/components/dashboard/people/role/RoleTab";
import { DirectoryTab } from "@/components/dashboard/people/directory/DirectoryTab";
import { useRouter, useSearchParams } from "next/navigation";
import PermissionGuard from "@/components/permissions/permission-protected-components";
import withPermissions from "@/components/permissions/permission-protected-routes";
import { useGetAllUsersApi, useGetDirectoryUsersApi } from "@/queries/users/get-all-users";
import { useGetAllDepartmentsApi } from "@/queries/departments/get-all-departments";
import { useGetAllRolesApi } from "@/queries/role/get-all-roles";
import { StatsCard } from "@/components/dashboard/landing/StatCard";
import { InviteEmployeesWarningModal } from "@/components/dashboard/people/modals/InviteEmployeesWarningModal";
import { useHeaderActionStore } from "@/stores/useHeaderActionStore";
import { useAuthStore } from "@/stores/auth-stores";

function People() {
    const can = useAuthStore(s => s.can);
    const canReadUsers      = can('user', 'read') || can('user', 'manage');
    const canReadDepts      = can('department', 'read') || can('department', 'manage');
    const canReadRoles      = can('role', 'read') || can('role', 'manage');
    const canReadDirectory  = can('user', 'read') || can('user', 'manage');

    const usersApi     = useGetAllUsersApi({ enabled: canReadUsers });
    const _deptsApi     = useGetAllDepartmentsApi({ enabled: canReadDepts });
    const rolesApi     = useGetAllRolesApi({ enabled: canReadRoles });
    const directoryApi = useGetDirectoryUsersApi({ enabled: canReadDirectory });

    const directoryTotalCount = directoryApi?.data?.meta?.totalCount ?? 0;
    const hasDirectoryData    = directoryTotalCount > 0;

    const uniqueDeptCount = useMemo(() => {
        const users: unknown[] = usersApi?.data?.data ?? [];
        const depts = new Set<string>();
        users.forEach((u) => {
            let deptName = "";
            if (!u.department) return;
            if (typeof u.department === "string") {
                deptName = u.department;
            } else if (typeof u.department === "object") {
                deptName = u.department.departmentName || u.department.name || "";
            }
            if (deptName) depts.add(deptName);
        });
        return depts.size;
    }, [usersApi?.data?.data]);

    const statCards = [
        { icon: Users,     label: "Total Users",   value: usersApi?.data?.meta?.totalCount || "0", description: "Total registered users",               bgColor: "#384A57" },
        { icon: CreditCard,label: "Active Cards",  value: "0",                                      description: "This month you spent extra $0.00",     bgColor: "#F45B69" },
        { icon: Building2, label: "Departments",   value: uniqueDeptCount,                          description: "View Departments",                      bgColor: "#5A67D8" },
        { icon: UserCog,   label: "Roles",         value: rolesApi?.data?.meta?.totalCount || "0",  description: "View Roles",                            bgColor: "#418341" },
        { icon: DollarSign,label: "Total Limits",  value: "$0.00",                                  description: "This month you spent extra $0.00",      bgColor: "#38B2AC" },
    ];

    const searchParams = useSearchParams();
    const router       = useRouter();

    const activeTab = searchParams.get("tab") || "all-users";
    const setActiveTab = (tab: string) => {
        const params = new URLSearchParams(searchParams.toString());
        params.set("tab", tab);
        router.replace(`?${params.toString()}`, { scroll: false });
    };

    const [isInviteModalOpen, setIsInviteModalOpen] = useState(false);

    // Register dynamic header CTA button
    const { setAction, clearAction } = useHeaderActionStore();
    const canManageUsers = useAuthStore(s => s.can)('user', 'manage');
    const _canManageRoles = useAuthStore(s => s.can)('role', 'manage');

    // Register the correct header button per tab
    useEffect(() => {
        if (activeTab === "all-users") {
            if (canManageUsers) {
                setAction({
                    label: "Invite Users",
                    dataTourId: "invite-button",
                    items: [
                        {
                            label: "Invite Employees",
                            onClick: () => setIsInviteModalOpen(true),
                        },
                        {
                            label: "Invite Leadership & Admin",
                            onClick: () => router.push("/people/invite/leadership"),
                        },
                    ],
                });
            } else {
                clearAction();
            }
        } else if (activeTab === "roles") {
            setAction({
                label: "Create Role",
                onClick: () => router.push("/people/create-role"),
            });
        } else if (activeTab === "directory") {
            if (canManageUsers) {
                setAction({
                    label: "Upload Directory",
                    dataTourId: "upload-directory-button",
                    iconName: "upload",
                    onClick: () => {
                        sessionStorage.setItem("uploadDirReferrer", "directory");
                        router.push("/people/invite/employees?step=upload");
                    },
                    secondaryAction: {
                        label: "Invite users",
                        iconName: "plus",
                        items: [
                            {
                                label: "Invite Employees",
                                onClick: () => setIsInviteModalOpen(true),
                            },
                            {
                                label: "Invite Leadership & Admin",
                                onClick: () => router.push("/people/invite/leadership"),
                            },
                        ],
                    }
                });
            } else {
                clearAction();
            }
        } else {
            clearAction();
        }

        return () => clearAction();
    }, [activeTab, setAction, clearAction, router]);

    return (
        <div className="bg-dashboard-bg min-h-screen">
            <div className="p-6 space-y-6">

                {/* Stats Grid */}
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-1.5">
                    {statCards.map((stat) => (
                        <StatsCard
                            key={stat.label}
                            title={stat.label}
                            value={stat.value}
                            isLoading={
                                stat.label === "Total Users"  ? usersApi.isLoading :
                                stat.label === "Departments"  ? usersApi.isLoading :
                                stat.label === "Roles"        ? rolesApi.isLoading : false
                            }
                            icon={
                                <div className="p-2 mr-3 flex items-center justify-center rounded-full text-white shrink-0" style={{ backgroundColor: stat.bgColor }}>
                                    <stat.icon className="w-5 h-5" />
                                </div>
                            }
                            subtitle={
                                <span className="text-xs leading-[125%]">{stat.description}</span>
                            }
                        />
                    ))}
                </div>

                {/* Tabs */}
                <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                        <TabsList className="bg-muted/50 p-1 h-auto rounded-lg">
                                <PermissionGuard resource="user" action="manage">
                                    <TabsTrigger
                                        value="all-users"
                                        className="data-[state=active]:bg-background rounded-md px-6"
                                    >
                                        Invited Users
                                    </TabsTrigger>
                                </PermissionGuard>
                                <PermissionGuard resource="role" action="manage">
                                    <TabsTrigger
                                        value="roles"
                                        className="data-[state=active]:bg-background rounded-md px-6"
                                    >
                                        Roles
                                    </TabsTrigger>
                                </PermissionGuard>
                                <PermissionGuard permissions={[
                                    { resource: "user", action: "manage" },
                                    { resource: "user", action: "read_company" }
                                ]}>
                                    <TabsTrigger
                                        value="directory"
                                        data-tour="directory-tab"
                                        className="data-[state=active]:bg-background rounded-md px-6"
                                    >
                                        Directory
                                    </TabsTrigger>
                                </PermissionGuard>
                            </TabsList>

                            <div id="tab-actions" className="flex items-center gap-2" />
                        </div>

                        <TabsContent value="all-users" className="mt-6">
                            <AllUsersTab />
                        </TabsContent>

                        <TabsContent value="roles" className="mt-6">
                            <RolesTab />
                        </TabsContent>

                        <TabsContent value="directory" className="mt-6">
                            <DirectoryTab />
                        </TabsContent>
                    </Tabs>
                </div>

                <InviteEmployeesWarningModal
                    isOpen={isInviteModalOpen}
                    onClose={() => setIsInviteModalOpen(false)}
                    onInviteLeaders={() => {
                        setIsInviteModalOpen(false);
                        router.push("/people/invite/leadership");
                    }}
                    onContinue={() => {
                        setIsInviteModalOpen(false);
                        router.push(
                            hasDirectoryData
                                ? "/people/invite/employees"
                                : "/people/invite/employees?step=upload"
                        );
                    }}
                />
            </div>
        );
    }

    export default withPermissions(People, [
        { resource: "user", action: "manage" },
        { resource: "user", action: "read" },
        { resource: "user", action: "read_company" },
        { resource: "role", action: "manage" },
        { resource: "department", action: "manage" }
    ]);

"use client"

import { useState } from "react";
import { ChevronDown, ChevronUp, ChevronRight, Edit2 } from "lucide-react";
import { Checkbox } from "@/components/ui/checkbox";
import { Badge } from "@/components/ui/badge";
import { useGetARoleApi } from "@/queries/role/get-a-role";
import { CapabilityGroup, CapabilitiesByModule, Role } from "@/queries/role/get-all-roles";
import { formatPermissionName } from "@/lib/utils";
import withPermissions from "@/components/permissions/permission-protected-routes";
import { useParams, useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import PermissionGuard from "@/components/permissions/permission-protected-components";
import ConfirmationModal from "@/components/modals/ConfirmationModal";
import { useDeleteRoleApi } from "@/queries/role/delete-role";
import toast from "react-hot-toast";

// ΓöÇΓöÇ Capability Group Card (expandable, read-only) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function CapabilityGroupCard({ group, index }: { group: CapabilityGroup; index: number }) {
    const [expanded, setExpanded] = useState(false);
    return (
        <div className="border border-slate-200 rounded-xl overflow-hidden">
            <div
                onClick={() => setExpanded(v => !v)}
                className="w-full flex items-start justify-between p-4 text-left hover:bg-slate-50 transition-colors cursor-pointer select-none"
            >
                <div className="flex items-start gap-3 flex-1 min-w-0">
                    <Checkbox
                        checked={true}
                        disabled
                        className="mt-0.5 w-4 h-4 border-2 border-primary data-[state=checked]:border-primary data-[state=checked]:bg-primary shrink-0"
                    />
                    <div className="min-w-0">
                        <p className="text-sm font-semibold text-slate-800">{index}. {group.name}</p>
                        <p className="text-xs text-slate-500 mt-0.5">{group.description}</p>
                    </div>
                </div>
                <div className="flex items-center gap-2 shrink-0 ml-3">
                    <span className="text-xs text-slate-400">{group.permissions.length} permissions</span>
                    {expanded
                        ? <ChevronUp className="w-4 h-4 text-slate-400" />
                        : <ChevronDown className="w-4 h-4 text-slate-400" />
                    }
                </div>
            </div>
            {expanded && (
                <div className="border-t border-slate-100 bg-slate-50/60 px-4 pb-4 pt-3">
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-y-2 gap-x-6">
                        {group.permissions.map(p => (
                            <div key={p.permissionId} className="flex items-center gap-2">
                                <div className="w-1.5 h-1.5 rounded-full bg-primary/60 shrink-0" />
                                <span className="text-xs text-slate-600">{formatPermissionName(p.name)}</span>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
}

// ΓöÇΓöÇ Module Section ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function ModuleSection({ moduleName, groups }: { moduleName: string; groups: CapabilityGroup[] }) {
    const [open, setOpen] = useState(true);
    const label = moduleName.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());

    return (
        <div className="space-y-3">
            <button
                type="button"
                onClick={() => setOpen(v => !v)}
                className="flex items-center gap-2 w-full text-left"
            >
                <span className="text-sm font-bold text-slate-700 uppercase tracking-widest">{label}</span>
                <div className="flex-1 h-px bg-slate-200" />
                {open ? <ChevronUp className="w-4 h-4 text-slate-400" /> : <ChevronDown className="w-4 h-4 text-slate-400" />}
            </button>
            {open && (
                <div className="space-y-2">
                    {groups.map((g, i) => <CapabilityGroupCard key={g.capabilityGroupId} group={g} index={i + 1} />)}
                </div>
            )}
        </div>
    );
}

// ΓöÇΓöÇ View Role Page ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function ViewRolePage() {
    const params = useParams();
    const router = useRouter();
    const roleId = params.roleId as string;
    const { data: roleData, isLoading } = useGetARoleApi(roleId, { enabled: !!roleId });
    const deleteRoleMutation = useDeleteRoleApi();
    const role = roleData?.data as Role | undefined;

    const [isDeleteModalOpen, setDeleteModalOpen] = useState(false);

    const handleDelete = async () => {
        try {
            await deleteRoleMutation.mutateAsync(roleId);
            toast.success("Role deleted successfully.");
            setDeleteModalOpen(false);
            router.push("/people?tab=roles");
        } catch (_error) {
            toast.error("Failed to delete the role.");
            setDeleteModalOpen(false);
        }
    };

    if (isLoading) {
        return (
            <div className="p-6">
                <div className="flex items-center justify-center h-64">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary" />
                </div>
            </div>
        );
    }

    if (!role) {
        return (
            <div className="p-6 text-center text-slate-400 text-sm">Role not found.</div>
        );
    }

    const roleName = role.name?.replace(/_/g, ' ') || "Role";
    const totalUsers = role.totalAssignedUsers || 0;

    // Capability groups from capabilitiesByModule
    const capModules: CapabilitiesByModule = (role as unknown).capabilitiesByModule ?? {};
    const hasCapabilities = Object.values(capModules).some(m => m.capabilityGroups?.length > 0);

    // Flat individual permissions (directly assigned, not from groups)
    const directPermissions = role.permissions ?? [];
    const hasDirectPermissions = directPermissions.length > 0;

    // Group direct permissions by resource for display
    const groupPermissionsByResource = (perms: unknown[]) => {
        const map: Record<string, { resource: string; permissions: unknown[] }> = {};
        for (const p of perms) {
            const res = p.resource || "other";
            if (!map[res]) map[res] = { resource: res, permissions: [] };
            map[res].permissions.push(p);
        }
        return Object.values(map);
    };
    const permissionGroups = groupPermissionsByResource(directPermissions);

    return (
        <div className="p-6 pt-0 space-y-6">
            {/* Header / Actions - Sticky */}
            <div className="flex items-center justify-between gap-4 sticky -top-5 z-50 bg-dashboard-background pt-5 pb-4 -mx-6 px-6 -mt-5">
                <h1 className="text-2xl font-semibold">Role Details</h1>

                <div className="flex items-center gap-3 shrink-0">
                    <PermissionGuard resource="role" action="manage">
                        <Button
                            variant="destructive"
                            size="sm"
                            className="gap-2"
                            onClick={() => setDeleteModalOpen(true)}
                        >
                            Delete Role
                        </Button>
                    </PermissionGuard>

                    <PermissionGuard resource="role" action="manage">
                        <Button
                            variant="outline"
                            size="sm"
                            className="gap-2 border-primary text-primary hover:bg-primary/5 bg-white"
                            onClick={() => router.push(`/people/create-role?id=${roleId}`)}
                        >
                            <Edit2 className="w-4 h-4" />
                            Edit Role
                        </Button>
                    </PermissionGuard>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-[300px_1fr] gap-10">
                {/* Sidebar */}
                <aside className="space-y-4 md:sticky md:top-24 self-start">
                    {/* Role Card */}
                    <div className="w-full flex items-center justify-between p-4 border-2 border-primary rounded-xl bg-white">
                        <div>
                            <div className="flex items-center gap-2 mb-1">
                                <p className="font-semibold text-primary capitalize">{roleName}</p>
                                <Badge variant={role.isActive ? "active" : "inactive"} className="text-xs">
                                    {role.isActive ? "Active" : "Inactive"}
                                </Badge>
                            </div>
                            <p className="text-sm text-slate-500 first-letter:uppercase">
                                {role.description || "No description provided."}
                            </p>
                            {role.source && (
                                <p className="text-xs text-slate-400 mt-1 capitalize">
                                    {role.isDefault ? "Default" : "Custom"} ┬╖ {role.source.replace(/_/g, ' ')}
                                </p>
                            )}
                        </div>
                        <ChevronRight className="w-5 h-5 text-primary flex-shrink-0" />
                    </div>

                    {/* User Count */}
                    <div className="border border-slate-200 rounded-xl p-4">
                        <div className="flex items-center gap-2">
                            <span className="text-sm font-semibold text-slate-700">Assigned Users</span>
                            <span className="text-sm font-bold text-primary">{totalUsers}</span>
                        </div>
                        {totalUsers === 0 && (
                            <p className="text-xs text-slate-400 mt-1">No users assigned to this role yet.</p>
                        )}
                    </div>
                </aside>

                {/* Main Content */}
                <main className="space-y-8">
                    {/* Section: Capabilities by Module */}
                    <div className="space-y-5">
                        <div className="flex items-center gap-2">
                            <h2 className="text-lg font-semibold text-slate-800">Capabilities</h2>
                            <span className="text-xs text-slate-400 font-normal">(grouped by module)</span>
                        </div>

                        {hasCapabilities ? (
                            <div className="space-y-8">
                                {(Array.isArray(capModules) ? capModules : Object.values(capModules)).map((modData: unknown) =>
                                    modData.capabilityGroups?.length > 0 ? (
                                        <ModuleSection key={modData.module || Math.random().toString()} moduleName={modData.module || "Unknown Module"} groups={modData.capabilityGroups} />
                                    ) : null
                                )}
                            </div>
                        ) : (
                            <div className="border border-dashed border-slate-200 rounded-xl p-8 text-center">
                                <p className="text-sm text-slate-400">No capability groups assigned to this role.</p>
                                <PermissionGuard resource="role" action="manage">
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        className="mt-3"
                                        onClick={() => router.push(`/people/create-role?id=${roleId}`)}
                                    >
                                        Assign Capabilities
                                    </Button>
                                </PermissionGuard>
                            </div>
                        )}
                    </div>

                    {/* Section: Directly Assigned Permissions */}
                    {hasDirectPermissions && (
                        <div className="space-y-5">
                            <div className="flex items-center gap-2">
                                <h2 className="text-lg font-semibold text-slate-800">Direct Permissions</h2>
                                <span className="text-xs text-slate-400 font-normal">(individually assigned)</span>
                            </div>
                            <div className="border border-slate-200 rounded-xl p-5 space-y-6">
                                {permissionGroups.map(group => (
                                    <div key={group.resource} className="space-y-3">
                                        <h3 className="text-xs font-bold text-slate-500 uppercase tracking-widest">
                                            {formatPermissionName(group.resource)}
                                        </h3>
                                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-y-2 gap-x-8">
                                            {group.permissions.map((p: unknown) => (
                                                <div key={p.permissionId} className="flex items-center gap-3">
                                                    <Checkbox
                                                        checked
                                                        disabled
                                                        className="w-4 h-4 border-2 border-primary data-[state=checked]:border-primary data-[state=checked]:bg-primary"
                                                    />
                                                    <label className="text-sm text-slate-600">
                                                        {formatPermissionName(p.name)}
                                                    </label>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    )}

                    {!hasCapabilities && !hasDirectPermissions && (
                        <div className="border border-dashed border-slate-200 rounded-xl p-10 text-center">
                            <p className="text-slate-400 text-sm">No capabilities or permissions assigned to this role.</p>
                        </div>
                    )}

                    <ConfirmationModal
                        isOpen={isDeleteModalOpen}
                        onClose={() => setDeleteModalOpen(false)}
                        onConfirm={handleDelete}
                        title="Delete Role"
                        description={
                            <>
                                Are you sure you want to delete <span className="font-semibold text-slate-900">{roleName}</span>?
                                Users assigned to this role might lose their access. This action cannot be undone.
                            </>
                        }
                    />
                </main>
            </div>
        </div>
    );
}

export default withPermissions(ViewRolePage, []);

