"use client";

import { useState, useEffect, useRef, useMemo } from "react";
import { useRouter, useParams, useSearchParams } from "next/navigation";
import { ManagerOverrideBanner } from "@/components/procurement/ManagerOverrideBanner";
import {
  Pencil, X, ChevronDown, AlertCircle, Loader2,
  Plus, Trash2, Calendar as CalendarIcon,
  Scissors, Check, Search,
} from "lucide-react";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Calendar as CalendarPicker } from "@/components/ui/calendar";
import { format } from "date-fns";
import { useAuthStore } from "@/stores/auth-stores";
import {
  useGetPurchaseRequestById,
  useUpdatePurchaseRequest,
  useAddLineItem,
  useUpdateLineItem,
  useDeleteLineItem,
  useSubmitPurchaseRequest,
  useWithdrawPurchaseRequest,
  useApprovePurchaseRequest,
  useRejectPurchaseRequest,
  useConvertToPO,
  useGetProcurementCategories,
  useGetVendors,
  type PurchaseRequest,
  type PurchaseRequestLineItem,
  type LineItemPayload,
  type CreatePurchaseRequestPayload,
  type Vendor,
} from "@/queries/procurement/purchase-requests";
import { useGetAllDepartmentsApi } from "@/queries/departments/get-all-departments";
import { toast } from "sonner";
import withPermissions from "@/components/permissions/permission-protected-routes";
import {
  PR_STATUS_CFG,
  getPRDisplayStatus,
} from "@/lib/constants/purchase-request-status";

// ΓöÇΓöÇΓöÇ Constants ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

const PRIORITIES = [
  { label: "Low", value: "low" },
  { label: "Medium", value: "medium" },
  { label: "High", value: "urgent" },
];

const CURRENCIES = ["USD", "NGN", "EUR", "GBP", "CAD", "AUD"];

const PRIORITY_LABELS: Record<string, string> = {
  low: "Low", medium: "Medium", urgent: "High",
};

// ΓöÇΓöÇΓöÇ Helpers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function formatAmount(n: number, currency = "USD") {
  const sym = currency === "USD" ? "$" : currency === "NGN" ? "Γéª" : currency === "EUR" ? "Γé¼" : currency === "GBP" ? "┬ú" : currency;
  return `${sym}${n.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
}

function formatDate(d?: string) {
  if (!d) return "ΓÇö";
  try { return new Date(d).toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" }); }
  catch { return d; }
}

function formatTs(d?: string) {
  if (!d) return "";
  try {
    const dt = new Date(d);
    const date = dt.toLocaleDateString("en-GB", { day: "2-digit", month: "2-digit", year: "numeric" }).replace(/\//g, "-");
    const time = dt.toLocaleTimeString("en-US", { hour: "2-digit", minute: "2-digit", hour12: true });
    return `${date}  ${time}`;
  } catch { return d; }
}

// ΓöÇΓöÇΓöÇ Status Badge ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

function StatusBadge({ status, approvalStatus }: { status: string; approvalStatus?: string | null }) {
  const displayKey = getPRDisplayStatus(status, approvalStatus);
  const cfg = PR_STATUS_CFG[displayKey] || PR_STATUS_CFG[status] || { label: status, className: "text-muted-foreground bg-muted/40" };
  return (
    <span className={`inline-flex items-center px-3 py-1 rounded-full text-xs font-semibold ${cfg.className}`}>
      {cfg.label}
    </span>
  );
}

function InfoCard({ label, value }: { label: string; value: string }) {
  return (
    <div className="bg-white rounded-xl border border-border p-4 flex-1 border-l-[3px] border-l-emerald-500">
      <p className="text-xs text-muted-foreground mb-1">{label}</p>
      <p className="text-base font-bold text-foreground">{value}</p>
    </div>
  );
}

function SimpleSelect({
  value, onChange, options, disabled = false,
}: {
  value: string; onChange: (v: string) => void;
  options: { label: string; value: string }[]; disabled?: boolean;
}) {
  const [open, setOpen] = useState(false);
  const selected = options.find(o => o.value === value);
  if (disabled) {
    return (
      <div className="w-full h-10 px-3 rounded-lg border border-border bg-muted/30 text-sm flex items-center text-foreground">
        {selected?.label || value}
      </div>
    );
  }
  return (
    <div className="relative">
      <button type="button" onClick={() => setOpen(v => !v)}
        className="w-full h-10 px-3 rounded-lg border border-border bg-muted/30 text-sm flex items-center justify-between hover:border-primary/60 focus:outline-none transition-colors">
        <span>{selected?.label || "Select..."}</span>
        <ChevronDown className={`w-4 h-4 text-muted-foreground transition-transform ${open ? "rotate-180" : ""}`} />
      </button>
      {open && (
        <div className="absolute left-0 right-0 z-50 bg-white border border-border rounded-xl shadow-lg mt-1 max-h-48 overflow-y-auto">
          {options.map(o => (
            <button key={o.value} type="button" onClick={() => { onChange(o.value); setOpen(false); }}
              className={`w-full text-left px-4 py-2.5 text-sm hover:bg-muted/40 transition-colors ${value === o.value ? "text-primary font-medium" : "text-foreground"}`}>
              {o.label}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Workflow Progress Sidebar ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

type StepStatus = "done" | "pending" | "inactive";
interface WorkflowStep {
  label: string;
  person?: string;
  timestamp?: string;
  badge?: string;
  badgeColor?: string;
  status: StepStatus;
}

function WorkflowProgress({ steps }: { steps: WorkflowStep[] }) {
  return (
    <div className="space-y-0">
      {steps.map((step, i) => (
        <div key={i} className="flex gap-3 items-start">
          <div className="relative flex flex-col items-center">
            <div className={`w-3.5 h-3.5 rounded-full border-2 shrink-0 mt-1 ${
              step.status === "done" ? "border-primary bg-primary"
              : step.status === "pending" ? "border-amber-400 bg-amber-100"
              : "border-gray-300 bg-white"}`} />
            {i < steps.length - 1 && <div className="w-px flex-1 bg-gray-200 mt-1 min-h-[28px]" />}
          </div>
          <div className="pb-5 min-w-0">
            <p className={`text-sm font-semibold leading-tight ${step.status === "inactive" ? "text-gray-400" : "text-foreground"}`}>
              {step.label}
            </p>
            {step.person && (
              <p className={`text-xs mt-0.5 ${step.status === "inactive" ? "text-gray-300" : "text-muted-foreground"}`}>
                {step.person}
                {step.badge && (
                  <span className={`ml-2 inline-flex items-center px-2 py-0.5 rounded-full text-[10px] font-semibold ${step.badgeColor}`}>
                    {step.badge}
                  </span>
                )}
              </p>
            )}
            {step.timestamp && <p className="text-[11px] text-muted-foreground/70 mt-0.5">{step.timestamp}</p>}
          </div>
        </div>
      ))}
    </div>
  );
