"use client";

import { useState, useEffect, useRef } from "react";
import { useRouter, useSearchParams } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Switch } from "@/components/ui/switch";
import { Pencil, Camera, Trash2, Loader2 } from "lucide-react";
import { useAuthStore } from "@/stores/auth-stores";
import { useAxios } from "@/hooks/useAxios";
import { API_KEYS } from "@/lib/constants/apis";
import { toast } from "sonner";
import { logger } from "@/lib/logger";
import { notifySetupGuide } from "@/lib/setupGuideEvents";
import { cn } from "@/lib/utils";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { 
  Select, 
  SelectContent, 
  SelectItem, 
  SelectTrigger, 
  SelectValue 
} from "@/components/ui/select";
import { useUpdateCompanyDetailsApi } from "@/queries/companies/update-company-details";
import { useOnboardingStore } from "@/stores/useVilletoStore";
import { getCurrencyConfig } from "@/lib/utils/currency";

// ΓöÇΓöÇΓöÇ Types ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
interface ProfileFormData {
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  country: string;
  city: string;
}

// ΓöÇΓöÇΓöÇ Notification toggle row ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function NotifRow({ label, defaultOn = false }: { label: string; defaultOn?: boolean }) {
  const [on, setOn] = useState(defaultOn);
  return (
    <div className="flex items-center justify-between py-3 border-b border-border last:border-0">
      <span className="text-sm text-foreground">{label}</span>
      <Switch checked={on} onCheckedChange={setOn} />
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Nigerian banks list ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
const NIGERIAN_BANKS = [
  "Access Bank",
  "Citibank Nigeria",
  "Ecobank Nigeria",
  "Fidelity Bank",
  "First Bank of Nigeria",
  "First City Monument Bank (FCMB)",
  "Guaranty Trust Bank (GTBank)",
  "Heritage Bank",
  "Keystone Bank",
  "Polaris Bank",
  "Providus Bank",
  "Stanbic IBTC Bank",
  "Standard Chartered Bank",
  "Sterling Bank",
  "SunTrust Bank",
  "Titan Trust Bank",
  "Union Bank of Nigeria",
  "United Bank for Africa (UBA)",
  "Unity Bank",
  "Wema Bank",
  "Zenith Bank",
];

// ΓöÇΓöÇΓöÇ Bank Details Modal ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function BankDetailsModal({
  open,
  onClose,
  onConfirm,
  accountHolderName,
}: {
  open: boolean;
  onClose: () => void;
  onConfirm: (bankName: string, accountNumber: string) => void;
  accountHolderName?: string;
}) {
  const [bankName, setBankName] = useState("");
  const [accountNumber, setAccountNumber] = useState("");

  const handleConfirm = () => {
    if (!bankName || !accountNumber) return;
    onConfirm(bankName, accountNumber);
    onClose();
  };

  if (!open) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center">
      {/* Backdrop */}
      <div className="absolute inset-0 bg-black/20" onClick={onClose} />
      {/* Modal */}
      <div className="relative bg-white rounded-2xl shadow-xl p-8 w-full max-w-md mx-4 z-10">
        <h2 className="text-lg font-semibold text-foreground mb-6">Bank Details</h2>

        {/* Bank Name */}
        <div className="mb-5">
          <label className="block text-sm font-medium text-foreground mb-2">Bank Name</label>
          <Select value={bankName} onValueChange={setBankName}>
            <SelectTrigger className="h-11 border-border bg-white text-sm">
              <SelectValue placeholder="Select bank" />
            </SelectTrigger>
            <SelectContent>
              {NIGERIAN_BANKS.map((bank) => (
                <SelectItem key={bank} value={bank}>
                  {bank}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        {/* Account Number */}
        <div className="mb-2">
          <label className="block text-sm font-medium text-foreground mb-2">Account Number</label>
          <Input
            value={accountNumber}
            onChange={(e) => {
              const val = e.target.value.replace(/\D/g, "").slice(0, 10);
              setAccountNumber(val);
            }}
            placeholder="Enter your 10 digits"
            className={cn(
              "h-11 border-border text-sm",
              accountNumber.length === 10 ? "border-primary" : ""
            )}
            maxLength={10}
          />
          {/* Account holder name preview */}
          {accountNumber.length === 10 && accountHolderName && (
            <p className="text-sm font-medium text-primary mt-1.5">{accountHolderName}</p>
          )}
        </div>

        {/* Actions */}
        <div className="flex items-center justify-end gap-4 mt-8">
          <button
            onClick={onClose}
            className="text-sm font-medium text-foreground underline-offset-2 hover:underline"
          >
            Cancel
          </button>
          <Button
            onClick={handleConfirm}
            disabled={!bankName || accountNumber.length < 10}
            className="bg-primary text-white hover:bg-primary/90 h-10 px-6 text-sm disabled:opacity-50"
          >
            Confirm
          </Button>
        </div>
      </div>
    </div>
  );
}

// ΓöÇΓöÇΓöÇ My Profile tab ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function MyProfileTab() {
  const user = useAuthStore((s) => s.user);
  const axios = useAxios();
  const [isEditing, setIsEditing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [avatarPreview, setAvatarPreview] = useState<string | null>(null);
  const avatarInputRef = useRef<HTMLInputElement>(null);

  // Bank details state
  const [bankModalOpen, setBankModalOpen] = useState(false);
  const [bankDetails, setBankDetails] = useState<{ bankName: string; accountNumber: string } | null>(null);

  const [form, setForm] = useState<ProfileFormData>({
    firstName: "",
    lastName: "",
    email: "",
    phone: "",
    country: "",
    city: "",
  });

  useEffect(() => {
    if (user) {
      setForm({
        firstName: user.firstName || "",
        lastName: String(user.lastName || ""),
        email: user.email || "",
        phone: String(user.phone || ""),
        country: user.company?.countryOfRegistration || "",
        city: "",
      });
    }
  }, [user]);

  const handleSave = async () => {
    setIsSaving(true);
    try {
      await axios.patch(API_KEYS.USER.ME, {
        firstName: form.firstName,
        lastName: form.lastName,
        phone: form.phone,
        city: form.city,
      });
      toast.success("Profile updated successfully");
      notifySetupGuide("account-details");
      setIsEditing(false);
    } catch (err) {
      logger.error("Profile update error:", err);
      toast.error("Failed to update profile");
    } finally {
      setIsSaving(false);
    }
  };

  const handleAvatarChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => setAvatarPreview(reader.result as string);
    reader.readAsDataURL(file);
  };

  const handleBankConfirm = (bankName: string, accountNumber: string) => {
    setBankDetails({ bankName, accountNumber });
    toast.success("Bank details updated successfully");
    notifySetupGuide("account-details");
  };

  const _Field = ({
    label,
    value,
    field,
    disabled,
    type = "text",
  }: {
    label: string;
    value: string;
    field: keyof ProfileFormData;
    disabled?: boolean;
    type?: string;
  }) => (
    <div className="space-y-1.5">
      <label className="text-sm font-medium text-foreground">
        {label}
        {!disabled && <span className="text-red-500 ml-0.5">*</span>}
      </label>
      <Input
        type={type}
        value={value}
        disabled={!isEditing || disabled}
        onChange={(e) => setForm((prev) => ({ ...prev, [field]: e.target.value }))}
        className={cn(
          "bg-muted/30 border-border h-11",
          (!isEditing || disabled) && "opacity-70 cursor-default"
        )}
      />
    </div>
  );

  const accountHolderName = `${form.firstName} ${form.lastName}`.trim() || user?.email;

  return (
    <div className="bg-white rounded-xl border border-border p-6" data-tour="account-details-section">
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-base font-semibold text-foreground">My Profile Details</h2>
        {!isEditing ? (
          <Button
            onClick={() => setIsEditing(true)}
            className="bg-primary text-white hover:bg-primary/90 h-9 px-4 gap-2 text-sm"
          >
            <Pencil className="w-3.5 h-3.5" />
            Edit Details
          </Button>
        ) : (
          <div className="flex gap-2">
            <Button
              variant="outline"
              onClick={() => setIsEditing(false)}
              className="h-9 px-4 text-sm"
            >
              Cancel
            </Button>
            <Button
              onClick={handleSave}
              disabled={isSaving}
              className="bg-primary text-white hover:bg-primary/90 h-9 px-4 text-sm"
            >
              {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : "Save Changes"}
            </Button>
          </div>
        )}
      </div>

      {/* Avatar */}
      <div className="mb-8 relative w-20">
        <div className="w-20 h-20 rounded-full overflow-hidden bg-muted border border-border">
          {avatarPreview ? (
            // eslint-disable-next-line @next/next/no-img-element
            <img src={avatarPreview} alt="Avatar" className="w-full h-full object-cover" />
          ) : (
            <div className="w-full h-full flex items-center justify-center text-2xl font-semibold text-muted-foreground bg-gradient-to-br from-primary/20 to-primary/10">
              {(user?.firstName?.[0] || "U").toUpperCase()}
            </div>
          )}
        </div>
        <button
          onClick={() => avatarInputRef.current?.click()}
          className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-7 h-7 rounded-full bg-primary flex items-center justify-center border-2 border-white"
        >
          <Camera className="w-3.5 h-3.5 text-white" />
        </button>
        <input ref={avatarInputRef} type="file" accept="image/*" className="hidden" onChange={handleAvatarChange} />
      </div>

      {/* Personal Details + Bank Details side by side */}
      <div className="grid grid-cols-1 lg:grid-cols-[1fr_auto] gap-6">
        {/* Personal Details Card */}
        <div className="border border-border rounded-xl p-5">
          <p className="text-xs font-bold uppercase tracking-wider text-foreground mb-5">Personal Details</p>
          <div className="grid grid-cols-2 gap-x-8 gap-y-5">
            <div className="space-y-1">
              <p className="text-xs text-muted-foreground">First Name</p>
              {isEditing ? (
                <Input
                  value={form.firstName}
                  onChange={(e) => setForm((p) => ({ ...p, firstName: e.target.value }))}
                  className="h-10 text-sm border-border bg-muted/30"
                />
              ) : (
                <p className="text-sm font-medium text-foreground">{form.firstName || "ΓÇö"}</p>
              )}
            </div>
            <div className="space-y-1">
              <p className="text-xs text-muted-foreground">Last Name</p>
              {isEditing ? (
                <Input
                  value={form.lastName}
                  onChange={(e) => setForm((p) => ({ ...p, lastName: e.target.value }))}
                  className="h-10 text-sm border-border bg-muted/30"
                />
              ) : (
                <p className="text-sm font-medium text-foreground">{form.lastName || "ΓÇö"}</p>
              )}
            </div>
            <div className="col-span-2 space-y-1">
              <p className="text-xs text-muted-foreground">Email Address</p>
              <p className="text-sm font-medium text-foreground">{form.email || "ΓÇö"}</p>
            </div>
            <div className="space-y-1">
              <p className="text-xs text-muted-foreground">Country</p>
              <p className="text-sm font-medium text-foreground">{form.country || "ΓÇö"}</p>
            </div>
            <div className="space-y-1">
              <p className="text-xs text-muted-foreground">City</p>
              {isEditing ? (
                <Input
                  value={form.city}
                  onChange={(e) => setForm((p) => ({ ...p, city: e.target.value }))}
                  className="h-10 text-sm border-border bg-muted/30"
                />
              ) : (
                <p className="text-sm font-medium text-foreground">{form.city || "ΓÇö"}</p>
              )}
            </div>
          </div>
        </div>

        {/* Bank Details Card */}
        <div className="border border-border rounded-xl p-5 min-w-[280px]">
          <p className="text-xs font-bold uppercase tracking-wider text-foreground mb-5">Bank Details</p>
          <div className="grid grid-cols-2 gap-x-6 gap-y-4 mb-5">
            <div className="space-y-1">
              <p className="text-xs text-muted-foreground">Account Number</p>
              <p className="text-sm font-medium text-foreground">{bankDetails?.accountNumber || "-"}</p>
            </div>
            <div className="space-y-1">
              <p className="text-xs text-muted-foreground">Bank Name</p>
              <p className="text-sm font-medium text-foreground">{bankDetails?.bankName || "-"}</p>
            </div>
          </div>
          <Button
            onClick={() => setBankModalOpen(true)}
            data-tour="update-details-button"
            className="bg-primary text-white hover:bg-primary/90 h-10 px-5 text-sm"
          >
            Update Details
          </Button>
        </div>
      </div>

      {/* Delete Account */}
      <div className="mt-6 rounded-xl bg-muted/30 border border-border p-5">
        <h3 className="text-sm font-semibold text-foreground mb-3">Delete Account</h3>
        <div className="flex items-start gap-2 mb-3">
          <div className="w-4 h-4 rounded-full border border-muted-foreground flex items-center justify-center shrink-0 mt-0.5">
            <span className="text-xs text-muted-foreground font-bold">i</span>
          </div>
          <p className="text-xs text-muted-foreground">
            After making a deletion request, you will have 1 month to recover your account.
          </p>
        </div>
        <p className="text-xs text-muted-foreground mb-4">
          To permanently delete your Villeto account, click the button below. You cannot reverse this action.
        </p>
        <button className="flex items-center gap-2 text-sm text-red-500 font-medium border border-red-200 rounded-lg px-4 py-2 hover:bg-red-50 transition-colors">
          <Trash2 className="w-4 h-4" />
          Delete Account
        </button>
      </div>

      {/* Bank Details Modal */}
      <BankDetailsModal
        open={bankModalOpen}
        onClose={() => setBankModalOpen(false)}
        onConfirm={handleBankConfirm}
        accountHolderName={accountHolderName}
      />
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Notifications tab ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
function NotificationsTab() {
  return (
    <div className="bg-white rounded-xl border border-border p-6">
      <h2 className="text-base font-semibold text-foreground mb-6">Notification Preferences</h2>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div>
          <h3 className="text-sm font-semibold text-foreground mb-3">Email Notifications</h3>
          <NotifRow label="Expense submissions" defaultOn />
          <NotifRow label="Approval updates" defaultOn />
          <NotifRow label="Card transactions" />
          <NotifRow label="Monthly reports" defaultOn />
          <NotifRow label="Policy violation alerts" defaultOn />
        </div>
        <div>
          <h3 className="text-sm font-semibold text-foreground mb-3">In-App Notifications</h3>
          <NotifRow label="Card alerts" defaultOn />
          <NotifRow label="Spending limit warnings" defaultOn />
          <NotifRow label="Pending approvals" defaultOn />
          <NotifRow label="Submission reminders" />
          <NotifRow label="Team activity" />
        </div>
      </div>
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Company Profile tab (full inline content ΓÇö same data as company-settings page) ΓöÇΓöÇ
interface CompanyData {
  companyId?: string;
  companyName?: string;
  businessName?: string;
  countryOfRegistration?: string;
  contactPhone?: string;
  contactNumber?: string;
  website?: string;
  websiteUrl?: string;
  industry?: string;
  companySize?: string;
  logo?: string;
  logoUrl?: string;
  bankStatus?: string;
  primaryCurrency?: string;
  currency?: string;
  spendLimit?: {
    lower: number;
    upper: number;
  };
  expectedMonthlySpend?: string;
}

interface AdminEntry {
  userId: string;
  firstName: string;
  lastName: string;
  position?: string;
  villetoRole?: { name: string };
}

function LogoUploader({
  currentLogo,
  companyName,
  onLogoChange,
}: {
  currentLogo?: string;
  companyName?: string;
  onLogoChange: (file: File, preview: string) => void;
}) {
  const inputRef = useRef<HTMLInputElement>(null);
  const handleFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = () => onLogoChange(file, reader.result as string);
    reader.readAsDataURL(file);
  };
  return (
    <div className="relative w-24 h-24 group cursor-pointer flex-shrink-0" onClick={() => inputRef.current?.click()}>
      <div className="w-24 h-24 rounded-full border border-border overflow-hidden bg-muted/30 flex items-center justify-center relative">
        {currentLogo ? (
          // eslint-disable-next-line @next/next/no-img-element
          <img src={currentLogo} alt="Company logo" className="w-full h-full object-cover" />
        ) : (
          <span className="text-4xl font-bold text-primary">
            {(companyName || "V").charAt(0).toUpperCase()}
          </span>
        )}
        <div className="absolute bottom-0 w-full h-7 bg-primary/90 flex items-center justify-center transition-opacity hover:bg-primary">
          <Pencil className="w-3.5 h-3.5 text-white" />
        </div>
      </div>
      <input ref={inputRef} type="file" accept="image/png,image/jpeg,image/jpg,image/svg+xml,image/webp" className="hidden" onChange={handleFile} />
    </div>
  );
}

function InfoRow({ 
  label, 
  value, 
  isEditing, 
  onChange, 
  renderEdit,
  disabled 
}: { 
  label: string; 
  value?: string; 
  isEditing?: boolean; 
  onChange?: (v: string) => void; 
  renderEdit?: () => React.ReactNode;
  disabled?: boolean;
}) {
  return (
    <div className="space-y-1">
      <p className="text-xs text-muted-foreground">{label}</p>
      {isEditing && !disabled ? (
        renderEdit ? renderEdit() : (
          <Input 
            value={value || ""} 
            onChange={(e) => onChange?.(e.target.value)}
            className="h-8 text-sm bg-gray-50 border-gray-200"
          />
        )
      ) : (
        <p className={cn("text-sm font-medium text-foreground", !value && "text-muted-foreground")}>
          {value || "ΓÇö"}
        </p>
      )}
    </div>
  );
}

function AdminAvatar({ admin }: { admin: AdminEntry }) {
  const first = admin.firstName?.[0] || "";
  const last = admin.lastName ? admin.lastName.toString()[0] : "";
  const initials = `${first}${last}`.toUpperCase();
  return (
    <div className="w-10 h-10 rounded-full bg-gradient-to-br from-primary/20 to-primary/10 flex items-center justify-center text-sm font-semibold text-primary shrink-0">
      {initials}
    </div>
  );
}

function CompanyProfileTab() {
  const user = useAuthStore((s) => s.user);
  const onboarding = useOnboardingStore();
  const axios = useAxios();
  const router = useRouter();
  const updateCompany = useUpdateCompanyDetailsApi();

  const [companyData, setCompanyData] = useState<CompanyData | null>(null);
  const [admins, setAdmins] = useState<AdminEntry[]>([]);
  const [realCompanySize, setRealCompanySize] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [logoPreview, setLogoPreview] = useState<string | null>(null);
  const [pendingLogoFile, setPendingLogoFile] = useState<File | null>(null);
  const [isSavingLogo, setIsSavingLogo] = useState(false);

  // Edit states
  const [isEditingInfo, setIsEditingInfo] = useState(false);
  const [isEditingFinancials, setIsEditingFinancials] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  const [infoForm, setInfoForm] = useState({
    businessName: "",
    country: "",
    phone: "",
    website: "",
    industry: ""
  });

  const [financialsForm, setFinancialsForm] = useState({
    spendIndex: 0,
    currency: ""
  });

  const spendIndexToLimits = (country: string, index: number) => {
    const config = getCurrencyConfig(country || "NGA");
    const range = config.spendingRanges[index] || config.spendingRanges[0];
    return { lower: range.lower, upper: range.upper };
  };

  const companyId = user?.companyId || user?.company?.companyId || user?.company?.id;

  useEffect(() => {
    // Initial logo from user store
    const storeLogo = user?.company?.logoUrl || user?.company?.logo;
    if (storeLogo) setLogoPreview(storeLogo);
  }, [user]);

  useEffect(() => {
    if (!user) return; // Wait for user to be populated
    if (!companyId) {
      setIsLoading(false);
      return;
    }
    const fetchData = async () => {
      try {
        setIsLoading(true);
        const results = await Promise.allSettled([
          axios.get(API_KEYS.COMPANY.COMPANY_DETAILS(companyId)),
          axios.get(API_KEYS.USER.USERS),
        ]);

        const compResult = results[0];
        const usersResult = results[1];

        let companyPayload = user?.company || {};
        if (compResult.status === 'fulfilled' && compResult.value?.data) {
          const resp = compResult.value.data;
          // Robust check for nested data: data.data.company...
          companyPayload = resp?.data?.company || resp?.data || resp || companyPayload;
        }
        setCompanyData(companyPayload as unknown);

        const fetchedLogo = companyPayload?.logoUrl || companyPayload?.logo || user?.company?.logoUrl || user?.company?.logo;
        if (fetchedLogo) setLogoPreview(fetchedLogo);

        if (usersResult.status === 'fulfilled' && usersResult.value?.data) {
          const usersData = usersResult.value.data;
          // Robust check for array: could be data.data (array) or data (array) or data.data.users (array)
          let allUsersResponse = [];
          if (Array.isArray(usersData?.data)) allUsersResponse = usersData.data;
          else if (Array.isArray(usersData)) allUsersResponse = usersData;
          else if (usersData?.data?.data && Array.isArray(usersData.data.data)) allUsersResponse = usersData.data.data;

          const meta = usersData?.meta || usersData?.data?.meta;
          const totalCount = meta?.totalCount || allUsersResponse.length;
          setRealCompanySize(totalCount.toString());

          const filteredAdmins = allUsersResponse
              .filter((u: unknown) => {
                const role = u.villetoRole?.name?.toUpperCase() || u.position?.toUpperCase() || "";
                return role !== "EMPLOYEE" && role !== "";
              })
              .slice(0, 6);
          setAdmins(filteredAdmins);

          // Sync form states
          const currentCountryCode = companyPayload?.countryOfRegistration || user?.company?.countryOfRegistration || onboarding?.businessSnapshot?.countryOfRegistration || "NGA";
          const config = getCurrencyConfig(currentCountryCode);

          let spendIdx = 0;
          if (companyPayload?.spendLimit?.lower !== undefined) {
             const idx = config.spendingRanges.findIndex(r => r.lower === companyPayload.spendLimit.lower);
             if (idx >= 0) spendIdx = idx;
          } else if (onboarding?.monthlySpend !== undefined) {
             spendIdx = onboarding.monthlySpend;
          }

          setInfoForm({
            businessName: companyPayload?.companyName || companyPayload?.businessName || user?.company?.companyName || onboarding?.businessSnapshot?.businessName || "",
            country: currentCountryCode,
            phone: companyPayload?.contactPhone || companyPayload?.contactNumber || user?.company?.phone || onboarding?.businessSnapshot?.contactNumber || "",
            website: companyPayload?.website || companyPayload?.websiteUrl || user?.company?.website || onboarding?.businessSnapshot?.website || "",
            industry: companyPayload?.industry || user?.company?.industry || ""
          });

          setFinancialsForm({
            spendIndex: spendIdx,
            currency: companyPayload?.primaryCurrency || companyPayload?.currency || user?.company?.currency || config.code || ""
          });

        } else {
          setRealCompanySize("ΓÇö");
        }
      } catch (err) {
        logger.error("Error fetching company data:", err);
      } finally {
        setIsLoading(false);
      }
    };
    fetchData();
  }, [user, companyId, axios]);

  const handleSaveInfo = async () => {
    setIsSaving(true);
    try {
      await updateCompany.mutateAsync({
        companyName: infoForm.businessName,
        countryOfRegistration: infoForm.country,
        contactPhone: infoForm.phone,
        websiteUrl: infoForm.website,
        industry: infoForm.industry
      });
      toast.success("Company information updated");
      setIsEditingInfo(false);
    } catch (_err) {
      toast.error("Failed to update company information");
    } finally {
      setIsSaving(false);
    }
  };

  const handleSaveFinancials = async () => {
    setIsSaving(true);
    try {
      const limits = spendIndexToLimits(infoForm.country, financialsForm.spendIndex);
      await updateCompany.mutateAsync({
        spendLimit: limits,
        primaryCurrency: financialsForm.currency
      });
      toast.success("Financial details updated");
      setIsEditingFinancials(false);
    } catch (_err) {
      toast.error("Failed to update financial details");
    } finally {
      setIsSaving(false);
    }
  };

  const handleLogoChange = (file: File, preview: string) => {
    setPendingLogoFile(file);
    setLogoPreview(preview);
  };

  const handleSaveLogo = async () => {
    if (!pendingLogoFile) return;
    setIsSavingLogo(true);
    try {
      const formData = new FormData();
      formData.append("file", pendingLogoFile, pendingLogoFile.name);
      await axios.post(API_KEYS.COMPANY.LOGO, formData, {
        headers: {
          "Content-Type": "multipart/form-data",
        },
      });
      toast.success("Company logo updated successfully");
      setPendingLogoFile(null);
      if (user?.companyId) {
        const res = await axios.get(API_KEYS.COMPANY.COMPANY_DETAILS(user.companyId));
        const updated = res?.data?.data || res?.data;
        if (updated?.logo) setLogoPreview(updated.logo);
      }
    } catch (err: unknown) {
      logger.error("Logo update error:", err);
      toast.info("Logo saved locally. Backend update will be available soon.");
      setPendingLogoFile(null);
    } finally {
      setIsSavingLogo(false);
    }
  };

  const filledFields = [
    companyData?.companyName, companyData?.countryOfRegistration,
    companyData?.contactPhone, companyData?.website,
    companyData?.industry, companyData?.logo || logoPreview,
    companyData?.expectedMonthlySpend,
  ].filter(Boolean).length;
  const completionPct = Math.round((filledFields / 7) * 100);

  if (isLoading) {
    return (
      <div className="flex items-center justify-center min-h-[40vh]">
        <Loader2 className="w-6 h-6 animate-spin text-primary" />
      </div>
    );
  }

  const LOCATION_MAP: Record<string, string> = { NGA: "Nigeria", GHA: "Ghana", KEN: "Kenya", ZAF: "South Africa" };
  const businessName = companyData?.companyName || companyData?.businessName || user?.company?.companyName || user?.company?.businessName || onboarding?.businessSnapshot?.businessName || "Company Details";
  const rawLocation = companyData?.countryOfRegistration || user?.company?.countryOfRegistration || onboarding?.businessSnapshot?.countryOfRegistration || "";
  const location = LOCATION_MAP[rawLocation] || rawLocation || "ΓÇö";

  const phone = companyData?.contactPhone || companyData?.contactNumber || user?.company?.phone || user?.company?.contactNumber || onboarding?.businessSnapshot?.contactNumber || "ΓÇö";
  const website = companyData?.website || companyData?.websiteUrl || user?.company?.website || user?.company?.websiteUrl || onboarding?.businessSnapshot?.website || "ΓÇö";
  const industry = companyData?.industry || user?.company?.industry || "ΓÇö";

  const config = getCurrencyConfig(rawLocation || "NGA");

  let expectedSpend = "ΓÇö";
  if (companyData?.spendLimit?.lower !== undefined) {
    const range = config.spendingRanges.find((r: unknown) => r.lower === companyData.spendLimit?.lower);
    if (range) expectedSpend = range.label;
    else expectedSpend = `${config.symbol}${companyData.spendLimit.lower} - ${config.symbol}${companyData.spendLimit.upper}`;
  } else if (companyData?.expectedMonthlySpend) {
    // Backend expectedMonthlySpend could be populated
    expectedSpend = companyData.expectedMonthlySpend;
  } else if (onboarding?.monthlySpend !== undefined && onboarding?.monthlySpend >= 0) {
    const range = config.spendingRanges[onboarding.monthlySpend];
    if (range) expectedSpend = range.label;
    else expectedSpend = onboarding.spendRange || "ΓÇö";
  } else if (onboarding?.spendRange) {
    expectedSpend = onboarding.spendRange;
  }

  const actCurrencyCode = companyData?.primaryCurrency || companyData?.currency || user?.company?.currency || config.code || "ΓÇö";
  const actCurrencyDisplay = actCurrencyCode !== "ΓÇö" ? `${config.symbol} ${actCurrencyCode}` : "ΓÇö";
  const currBankStatus = companyData?.bankStatus || (onboarding?.bankConnected ? "Connected" : "Not connected");

  return (
    <div className="space-y-4 pt-2">
      <div className="flex items-center">
         <h1 className="text-xl font-bold text-foreground">Company Details</h1>
      </div>

      {/* Header card */}
      <div className="bg-white rounded-xl border border-border px-8 py-6">
        <div className="flex items-start justify-between">
          <div className="flex items-center gap-6">
            <LogoUploader 
              currentLogo={logoPreview || undefined} 
              companyName={businessName}
              onLogoChange={handleLogoChange} 
            />
            <div className="flex flex-col">
              <h2 className="text-[22px] font-bold text-foreground leading-none mb-2">{businessName}</h2>
              <p className="text-sm text-muted-foreground">{location}</p>
              {pendingLogoFile && (
                <Button size="sm" onClick={handleSaveLogo} disabled={isSavingLogo}
                  className="mt-3 h-8 px-4 text-xs bg-primary text-white hover:bg-primary/90 w-fit">
                  {isSavingLogo ? <Loader2 className="w-3 h-3 animate-spin mr-2" /> : null}
                  {isSavingLogo ? "Saving..." : "Save Logo"}
                </Button>
              )}
            </div>
          </div>
          <div className="text-right min-w-[200px] flex flex-col justify-center h-full">
            <p className="text-sm font-medium text-foreground mb-1">Profile Completion</p>
            <div className="flex items-center gap-2 justify-end mb-2">
              <div className="flex-1 h-2 bg-muted rounded-full overflow-hidden w-32">
                <div className="h-full bg-primary rounded-full transition-all" style={{ width: `${completionPct}%` }} />
              </div>
              <span className="text-xs font-semibold text-foreground">{completionPct}%</span>
            </div>
            <Button size="sm" className="h-8 px-4 text-xs bg-foreground text-white hover:bg-foreground/90 rounded-lg">
              Finish setup
            </Button>
          </div>
        </div>
      </div>

      {/* Two-column body */}
      <div className="grid grid-cols-[1fr_300px] gap-5">
        <div className="space-y-5">
          <div className="bg-white rounded-xl border border-border p-5">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-xs font-bold uppercase tracking-wider text-foreground">Profile Information</h2>
              {!isEditingInfo ? (
                <button 
                  onClick={() => setIsEditingInfo(true)}
                  className="text-primary hover:text-primary/80 transition-colors cursor-pointer p-1 rounded-md hover:bg-primary/5"
                >
                  <Pencil className="w-4 h-4" />
                </button>
              ) : (
                <div className="flex gap-2">
                  <button onClick={() => setIsEditingInfo(false)} className="text-xs font-medium text-muted-foreground hover:text-foreground">Cancel</button>
                  <button onClick={handleSaveInfo} disabled={isSaving} className="text-xs font-bold text-primary hover:text-primary/80 disabled:opacity-50">
                    {isSaving ? "Saving..." : "Save"}
                  </button>
                </div>
              )}
            </div>
            <div className="grid grid-cols-2 gap-x-8 gap-y-4">
              <InfoRow 
                label="Business Name" 
                value={isEditingInfo ? infoForm.businessName : businessName} 
                isEditing={isEditingInfo}
                onChange={(v) => setInfoForm(p => ({ ...p, businessName: v }))}
              />
              <InfoRow 
                label="Country" 
                value={isEditingInfo ? infoForm.country : location} 
                isEditing={isEditingInfo}
                renderEdit={() => (
                  <Select 
                    value={infoForm.country} 
                    onValueChange={(v) => {
                      setInfoForm(p => ({ ...p, country: v }));
                      const newConfig = getCurrencyConfig(v);
                      setFinancialsForm(p => ({ ...p, currency: newConfig.code }));
                    }}
                  >
                    <SelectTrigger className="h-8 w-full bg-gray-50 border-gray-200">
                      <SelectValue placeholder="Select Country" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="NGA">Nigeria</SelectItem>
                      <SelectItem value="GHA">Ghana</SelectItem>
                      <SelectItem value="KEN">Kenya</SelectItem>
                      <SelectItem value="ZAF">South Africa</SelectItem>
                    </SelectContent>
                  </Select>
                )}
              />
              <InfoRow 
                label="Phone Number" 
                value={isEditingInfo ? infoForm.phone : phone} 
                isEditing={isEditingInfo}
                onChange={(v) => setInfoForm(p => ({ ...p, phone: v }))}
              />
              <InfoRow 
                label="Website" 
                value={isEditingInfo ? infoForm.website : website} 
                isEditing={isEditingInfo}
                onChange={(v) => setInfoForm(p => ({ ...p, website: v }))}
              />
              <InfoRow 
                label="Industry" 
                value={isEditingInfo ? infoForm.industry : industry} 
                isEditing={isEditingInfo}
                onChange={(v) => setInfoForm(p => ({ ...p, industry: v }))}
              />
              <InfoRow 
                label="Company Size" 
                value={realCompanySize || companyData?.companySize} 
                disabled // Read only as requested
              />
            </div>
          </div>

          <div className="bg-white rounded-xl border border-border p-5">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-xs font-bold uppercase tracking-wider text-foreground">Financial Snapshot</h2>
              {!isEditingFinancials ? (
                <button 
                  onClick={() => setIsEditingFinancials(true)}
                  className="text-primary hover:text-primary/80 transition-colors cursor-pointer p-1 rounded-md hover:bg-primary/5"
                >
                  <Pencil className="w-4 h-4" />
                </button>
              ) : (
                <div className="flex gap-2">
                  <button onClick={() => setIsEditingFinancials(false)} className="text-xs font-medium text-muted-foreground hover:text-foreground">Cancel</button>
                  <button onClick={handleSaveFinancials} disabled={isSaving} className="text-xs font-bold text-primary hover:text-primary/80 disabled:opacity-50">
                    {isSaving ? "Saving..." : "Save"}
                  </button>
                </div>
              )}
            </div>
            <div className="grid grid-cols-2 gap-x-8 gap-y-4">
              <InfoRow 
                label="Expected Monthly Spend" 
                value={isEditingFinancials ? config.spendingRanges[financialsForm.spendIndex]?.label : expectedSpend} 
                isEditing={isEditingFinancials}
                renderEdit={() => {
                  const currentConfig = getCurrencyConfig(infoForm.country || "NGA");
                  return (
                    <div className="space-y-4 pt-4 col-span-2">
                      <div className="flex justify-between items-center mb-1">
                         <span className="text-xs text-muted-foreground">Adjust Range</span>
                         <span className="text-sm font-bold text-primary">{currentConfig.spendingRanges[financialsForm.spendIndex]?.label}</span>
                      </div>
                      <div className="relative h-6 flex items-center">
                        <div className="absolute w-full h-1 bg-muted rounded-full">
                           <div className="h-full bg-primary rounded-full" style={{ width: `${(financialsForm.spendIndex / 3) * 100}%` }} />
                        </div>
                        <input 
                           type="range" min="0" max="3" step="1" 
                           value={financialsForm.spendIndex} 
                           onChange={(e) => setFinancialsForm(p => ({ ...p, spendIndex: parseInt(e.target.value) }))}
                           className="absolute w-full h-6 opacity-0 cursor-pointer z-10"
                        />
                        <div className="absolute w-4 h-4 bg-white border-2 border-primary rounded-full shadow-sm" 
                             style={{ left: `calc(${(financialsForm.spendIndex / 3) * 100}% - 8px)` }} 
                        />
                      </div>
                      <div className="flex justify-between px-1">
                        {currentConfig.spendingRanges.map((r, i) => (
                           <span key={i} className={cn("text-[10px] cursor-pointer hover:text-primary", financialsForm.spendIndex === i ? "text-primary font-bold" : "text-muted-foreground")}
                                 onClick={() => setFinancialsForm(p => ({ ...p, spendIndex: i }))}>
                              {r.label.split(' ')[0]}
                           </span>
                        ))}
                      </div>
                    </div>
                  );
                }}
              />
              <InfoRow 
                label="Primary Currency" 
                value={isEditingFinancials ? financialsForm.currency : actCurrencyDisplay} 
                isEditing={isEditingFinancials}
                renderEdit={() => (
                  <div className="h-8 flex items-center px-3 rounded-md bg-muted/50 border border-border text-sm font-medium text-muted-foreground">
                    {financialsForm.currency}
                  </div>
                )}
              />
              <div className="space-y-1">
                <p className="text-xs text-muted-foreground">Bank Status</p>
                <span className={cn("inline-block text-xs font-medium px-2.5 py-0.5 rounded-full",
                  currBankStatus === "Connected" ? "bg-green-100 text-green-700" : "bg-muted text-muted-foreground")}>
                  {currBankStatus}
                </span>
              </div>
            </div>
            <Button variant="outline" size="sm" className="mt-4 text-xs h-8 border-primary text-primary hover:bg-primary/10">
              Manage connection
            </Button>
          </div>
        </div>

        <div className="bg-white rounded-xl border border-border p-5">
          <h2 className="text-xs font-bold uppercase tracking-wider text-foreground mb-4">Administrators &amp; Owners</h2>
          {admins.length === 0 ? (
            <p className="text-sm text-muted-foreground py-4 text-center">No admins found</p>
          ) : (
            <div className="space-y-3 mb-5">
              {admins.map((admin) => (
                <div key={admin.userId} className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <AdminAvatar admin={admin} />
                    <div>
                      <p className="text-sm font-semibold text-foreground leading-tight">{admin.firstName} {admin.lastName}</p>
                      <p className="text-[13px] text-muted-foreground capitalize mt-0.5">
                        {((admin.villetoRole?.name || admin.position || "Admin") as string).toLowerCase().replace(/_/g, ' ')}
                      </p>
                    </div>
                  </div>
                  <button className="text-sm font-medium text-muted-foreground hover:text-foreground">Manage</button>
                </div>
              ))}
            </div>
          )}
          <div className="flex gap-2 pt-2 border-t border-border">
            <Button variant="outline" size="sm" className="flex-1 h-8 text-xs" onClick={() => router.push("/people")}>
              View Permission
            </Button>
            <Button size="sm" className="flex-1 h-8 text-xs bg-white border border-primary text-primary hover:bg-primary/10"
              onClick={() => router.push("/people/invite/leadership")}>
              Invite Admin
            </Button>
          </div>
        </div>
      </div>
    </div>
  );
}

// ΓöÇΓöÇΓöÇ Page ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
export default function PersonalSettingsPage() {
  const _user = useAuthStore((s) => s.user);
  const searchParams = useSearchParams();
  const router = useRouter();

  const canSeeCompany = useAuthStore((s) => s.can)("user", "manage");

  // Drive active tab from URL ?tab= so the sidebar "Company Settings" link
  // can deep-link here with ?tab=company-profile
  const tabParam = searchParams.get("tab");
  const defaultTab =
    tabParam === "company-profile" && canSeeCompany
      ? "company-profile"
      : tabParam === "notifications"
      ? "notifications"
      : "my-profile";

  const handleTabChange = (value: string) => {
    router.replace(`/settings/personal-settings?tab=${value}`, { scroll: false });
  };

  return (
    <div className="max-w-5xl mx-auto py-6 px-4">
      <Tabs value={defaultTab} onValueChange={handleTabChange}>
        <TabsList className="bg-muted/50 p-1 h-auto rounded-lg mb-6">
          <TabsTrigger value="my-profile" className="data-[state=active]:bg-background rounded-md px-6">
            My Profile
          </TabsTrigger>
          {canSeeCompany && (
            <TabsTrigger value="company-profile" className="data-[state=active]:bg-background rounded-md px-6">
              Company Profile
            </TabsTrigger>
          )}
          <TabsTrigger value="notifications" className="data-[state=active]:bg-background rounded-md px-6">
            Notifications
          </TabsTrigger>
        </TabsList>

        <TabsContent value="my-profile">
          <MyProfileTab />
        </TabsContent>

        {canSeeCompany && (
          <TabsContent value="company-profile">
            <CompanyProfileTab />
          </TabsContent>
        )}

        <TabsContent value="notifications">
          <NotificationsTab />
        </TabsContent>
      </Tabs>
    </div>
  );
}

"use client";

import { useEffect, useState } from "react";
import { useParams, useRouter } from "next/navigation";
import { useAxios } from "@/hooks/useAxios";
import { Skeleton } from "@/components/ui/skeleton";
import { logger } from "@/lib/logger";
import { CheckCircle2, XCircle, X, FileText } from "lucide-react";
import { useAuthStore } from "@/stores/auth-stores";
import { toast } from "sonner";
import withPermissions from "@/components/permissions/permission-protected-routes";

export default withPermissions(VendorDetailsPage, [
  { resource: "vendor", action: "read_company" },
  { resource: "vendor", action: "manage" },
]);

function VendorDetailsPage() {
  const { vendorId } = useParams() as { vendorId: string };
  const router = useRouter();
  const axiosInstance = useAxios();
  const can = useAuthStore(s => s.can);

  const [vendor, setVendor] = useState<unknown>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [requestInfoModalOpen, setRequestInfoModalOpen] = useState(false);
  const [infoMessage, setInfoMessage] = useState("");
  const [rejectModalOpen, setRejectModalOpen] = useState(false);
  const [rejectReason, setRejectReason] = useState("");

  const fetchVendor = async () => {
    setIsLoading(true);
    try {
      const res = await axiosInstance.get(`/vendors/${vendorId}`);
      setVendor(res.data.data);
    } catch (err) {
      logger.error("Error fetching vendor details:", err);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (vendorId) fetchVendor();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [vendorId]);

  const handleDecision = async (decision: "approved" | "rejected", customNote?: string) => {
    if (!vendor) return;
    setIsSubmitting(true);
    const note = customNote || (decision === "approved" ? "KYC and banking details reviewed." : `Vendor ${decision} by admin.`);
    try {
      await axiosInstance.patch(`/vendors/${vendorId}/review`, { decision, decisionNote: note });
      fetchVendor();
      if (decision === "rejected") { setRejectModalOpen(false); setRejectReason(""); }
      toast.success(decision === "approved" ? "Vendor approved successfully" : "Vendor rejected");
    } catch (err) {
      logger.error(`Failed to ${decision} vendor`, err);
      toast.error(`Failed to ${decision} vendor. Please try again.`);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleStatusUpdate = async (statusPayload: "Active" | "Inactive") => {
    setIsSubmitting(true);
    try {
      await axiosInstance.patch(`/vendors/${vendorId}/status`, { status: statusPayload });
      fetchVendor();
      toast.success(`Vendor ${statusPayload === "Active" ? "activated" : "deactivated"} successfully`);
    } catch (err) {
      logger.error(`Failed to update vendor status to ${statusPayload}`, err);
      toast.error(`Failed to ${statusPayload === "Active" ? "activate" : "deactivate"} vendor. Please try again.`);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleResendInvitation = async () => {
    setIsSubmitting(true);
    try {
      await axiosInstance.post(`/vendors/${vendorId}/invitations/resend`);
      toast.success("Invitation resent successfully");
    } catch (err) {
      logger.error(`Failed to resend invitation`, err);
      toast.error("Failed to resend invitation. Please try again.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleRequestInfo = async () => {
    logger.log("Request info sent:", infoMessage);
    setRequestInfoModalOpen(false);
    setInfoMessage("");
  };

  if (isLoading) {
    return (
      <div className="space-y-6">
        <Skeleton className="h-8 w-16" />
        <Skeleton className="h-12 w-1/3" />
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
          <Skeleton className="h-[400px] w-full" />
          <Skeleton className="h-[400px] w-full" />
        </div>
      </div>
    );
  }

  if (!vendor) {
    return <div><p className="text-muted-foreground">Vendor not found.</p></div>;
  }

  const rawStatus        = (vendor.status        || "").toLowerCase();
  const onboardingStatus = vendor.onboardingStatus || "";
  const approvalStatus   = vendor.approvalStatus  || "";

  const isInvited     = approvalStatus === "pending" && (!onboardingStatus || onboardingStatus === "invited");
  const isOnboarding  = approvalStatus === "pending" && !["invited", "submitted", ""].includes(onboardingStatus);
  const isUnderReview = approvalStatus === "pending" && onboardingStatus === "submitted";
  const isRejected    = approvalStatus === "rejected";
  const isApprovedPhase4 = approvalStatus === "approved" && rawStatus !== "active" && !vendor.deactivatedAt;
  const isDeactivated    = approvalStatus === "approved" && rawStatus !== "active" && !!vendor.deactivatedAt;
  const isActive         = approvalStatus === "approved" && rawStatus === "active";

  // Risk flag only makes sense once the vendor has completed onboarding and submitted for review.
  // Invited vendors are expected to lack bank details ΓÇö flagging them is misleading.
  const isEligibleForRiskCheck = isUnderReview || isApprovedPhase4 || isActive;
  const hasBankMismatch = isEligibleForRiskCheck && (!vendor.bankName || !vendor.bankAccountNumber);
  const riskLevel = hasBankMismatch ? "High" : "Low";

  return (
    <div className="space-y-6 animate-in fade-in duration-300">

      {/* ΓöÇΓöÇ Header ΓöÇΓöÇ */}
      <div className="flex flex-col md:flex-row md:items-start justify-between gap-4">
        <div>
          <div className="flex items-center gap-3">
            <h1 className="text-2xl font-semibold text-foreground">{vendor.legalName || vendor.displayName}</h1>
            {isOnboarding  && <span className="px-2.5 py-0.5 rounded-full bg-blue-50 text-blue-500 text-xs font-semibold border border-blue-100">Onboarding</span>}
            {isUnderReview && <span className="px-2.5 py-0.5 rounded-full bg-amber-50 text-amber-500 text-xs font-semibold border border-amber-100">Under Review</span>}
            {isActive      && <span className="px-2.5 py-0.5 rounded-full bg-emerald-50 text-emerald-600 text-xs font-semibold border border-emerald-100">Active</span>}
            {isApprovedPhase4 && <span className="px-2.5 py-0.5 rounded-full bg-emerald-50 text-emerald-600 text-xs font-semibold border border-emerald-100">Approved</span>}
            {isDeactivated && <span className="px-2.5 py-0.5 rounded-full bg-gray-100 text-gray-600 text-xs font-semibold border border-gray-200">Deactivated</span>}
            {isRejected    && <span className="px-2.5 py-0.5 rounded-full bg-red-50 text-red-500 text-xs font-semibold border border-red-100">Rejected</span>}
            {isInvited     && <span className="px-2.5 py-0.5 rounded-full bg-gray-100 text-gray-500 text-xs font-semibold border border-gray-200">Invited</span>}
          </div>
          <p className="text-sm font-medium text-muted-foreground mt-1">{vendor.email}</p>
        </div>

        <div className="flex items-center gap-3">
          {/* Approve / Reject / Request Info ΓÇö Authorization: can('vendor','approve') + Workflow: isUnderReview */}
          {isUnderReview && can('vendor', 'reject') && (
            <button disabled={isSubmitting} onClick={() => setRejectModalOpen(true)}
              className="px-5 h-10 rounded-xl border border-destructive text-destructive font-semibold text-sm hover:bg-destructive/10 transition-colors disabled:opacity-50">
              Reject vendor
            </button>
          )}
          {isUnderReview && can('vendor', 'review') && (
            <button disabled={isSubmitting} onClick={() => setRequestInfoModalOpen(true)}
              className="px-5 h-10 rounded-xl border border-[#00BFA5] text-[#00BFA5] font-semibold text-sm hover:bg-[#00BFA5]/5 transition-colors disabled:opacity-50">
              Request Info
            </button>
          )}
          {isUnderReview && can('vendor', 'approve') && (
            <button disabled={isSubmitting} onClick={() => handleDecision("approved")}
              className="px-5 h-10 rounded-xl bg-[#00BFA5] text-white font-semibold text-sm hover:opacity-90 transition-opacity disabled:opacity-50">
              {isSubmitting ? "Processing..." : "Approve vendor"}
            </button>
          )}
          {/* Activate ΓÇö Authorization: can('vendor','activate') + Workflow: isApprovedPhase4 || isDeactivated */}
          {(isApprovedPhase4 || isDeactivated) && can('vendor', 'activate') && (
            <button disabled={isSubmitting} onClick={() => handleStatusUpdate("Active")}
              className="px-5 h-10 rounded-xl bg-primary text-primary-foreground font-semibold text-sm hover:opacity-90 transition-opacity disabled:opacity-50">
              {isSubmitting ? "Processing..." : isDeactivated ? "Reactivate vendor" : "Activate vendor"}
            </button>
          )}
          {/* Deactivate ΓÇö Authorization: can('vendor','deactivate') + Workflow: isActive */}
          {isActive && can('vendor', 'deactivate') && (
            <button disabled={isSubmitting} onClick={() => handleStatusUpdate("Inactive")}
              className="px-5 h-10 rounded-xl bg-transparent border border-destructive text-destructive font-semibold text-sm hover:bg-destructive/5 transition-colors disabled:opacity-50">
              {isSubmitting ? "Processing..." : "Deactivate vendor"}
            </button>
          )}
          {/* Resend Invitation ΓÇö Authorization: can('vendor','invite') + Workflow: isInvited || isOnboarding */}
          {(isInvited || isOnboarding) && can('vendor', 'invite') && (
            <button disabled={isSubmitting} onClick={handleResendInvitation}
              className="px-5 h-10 rounded-xl bg-[#00BFA5] text-white font-semibold text-sm hover:opacity-90 transition-opacity disabled:opacity-50 cursor-pointer">
              {isSubmitting ? "Sending..." : "Resend Invitation"}
            </button>
          )}
        </div>
      </div>

      {/* ΓöÇΓöÇ Content Grid: equal 50/50 columns ΓöÇΓöÇ */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-start">

        {/* ΓòÉΓòÉ Left Column ΓòÉΓòÉ */}
        <div className="space-y-6">

          {/* Identity Verification
              FIX: outer padding p-8 ΓåÆ p-6 so inner row cards feel anchored to the container
              FIX: each field row = ONE unified bordered card (not individual mini-cards)
              FIX: value font-size text-xl ΓåÆ text-base (matches Figma weight)
              FIX: labels are sentence-case text-sm, not tiny uppercase  */}
          <div className="bg-white rounded-3xl border border-border p-6 shadow-sm">
            <h2 className="text-xs font-semibold text-muted-foreground uppercase tracking-widest mb-5">IDENTITY VERIFICATION</h2>

            <div className="space-y-3">
              {/* Row 1 ΓÇö single card, two fields inside */}
              <div className="border border-border/50 rounded-xl p-4">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <p className="text-sm font-medium text-muted-foreground mb-1">Business Name</p>
                    <p className="text-sm font-semibold text-foreground">{vendor.legalName || "N/A"}</p>
                  </div>
                  <div>
                    <p className="text-sm font-medium text-muted-foreground mb-1">Registration Number</p>
                    <p className="text-sm font-semibold text-foreground">{vendor.taxId || "N/A"}</p>
                  </div>
                </div>
              </div>

              {/* Row 2 */}
              <div className="border border-border/50 rounded-xl p-4">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <p className="text-sm font-medium text-muted-foreground mb-1">Bank</p>
                    <p className="text-sm font-semibold text-foreground">{vendor.bankName || "N/A"}</p>
                  </div>
                  <div>
                    <p className="text-sm font-medium text-muted-foreground mb-1">Account</p>
                    <p className="text-sm font-semibold text-foreground">{vendor.bankAccountNumber || "N/A"}</p>
                  </div>
                </div>
              </div>

              {/* Row 3 */}
              <div className="border border-border/50 rounded-xl p-4">
                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <p className="text-sm font-medium text-muted-foreground mb-1">Country</p>
                    <p className="text-sm font-semibold text-foreground">{vendor.country || "N/A"}</p>
                  </div>
                  <div className="overflow-hidden">
                    <p className="text-sm font-medium text-muted-foreground mb-1">Address</p>
                    <p className="text-sm font-semibold text-foreground truncate" title={vendor.address}>
                      {vendor.address || "N/A"}
                    </p>
                  </div>
                </div>
              </div>

              {/* Row 4: Created & Approved */}
              {(vendor.createdBy || vendor.approvedBy) && (
                <div className="border border-border/50 rounded-xl p-4">
                  <div className="grid grid-cols-2 gap-4">
                    {vendor.createdBy && (
                      <div>
                        <p className="text-sm font-medium text-muted-foreground mb-1">Invited By</p>
                        <p className="text-sm font-semibold text-foreground">{vendor.createdBy.firstName} {vendor.createdBy.lastName}</p>
                      </div>
                    )}
                    {vendor.approvedBy && (
                      <div>
                        <p className="text-sm font-medium text-muted-foreground mb-1">Approved By</p>
                        <p className="text-sm font-semibold text-foreground">{vendor.approvedBy.firstName} {vendor.approvedBy.lastName}</p>
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Verification Documents ΓÇö outer padding p-8 ΓåÆ p-6 to stay consistent */}
          <div className="bg-white rounded-3xl border border-border p-6 shadow-sm">
            <h2 className="text-xs font-semibold text-muted-foreground uppercase tracking-widest mb-5">VERIFICATION DOCUMENTS</h2>
            {vendor.documents && vendor.documents.length > 0 ? (
              <div className="space-y-3">
                {vendor.documents.map((doc: unknown) => (
                  <div key={doc.vendorDocumentId}
                    className="flex items-center justify-between p-4 rounded-xl border border-border bg-white">
                    <div className="flex items-center gap-3">
                      <div className="w-9 h-9 rounded-full bg-primary/10 flex items-center justify-center shrink-0">
                        <CheckCircle2 className="w-5 h-5 text-primary" />
                      </div>
                      <div>
                        <p className="text-sm font-semibold text-foreground">{doc.originalName || "Document.pdf"}</p>
                        <p className="text-xs text-muted-foreground capitalize">{doc.documentType.replace(/_/g, " ")}</p>
                      </div>
                    </div>
                    <a href={doc.fileUrl} target="_blank" rel="noreferrer"
                      className="px-5 py-1.5 rounded-xl border border-primary text-primary text-xs font-bold hover:bg-primary/5 transition-colors">
                      View
                    </a>
                  </div>
                ))}
              </div>
            ) : (
              <p className="text-sm font-medium text-muted-foreground">No documents uploaded.</p>
            )}
          </div>
        </div>

        {/* ΓòÉΓòÉ Right Column ΓòÉΓòÉ */}
        <div className="space-y-6">

          {/* Risk Analysis ΓÇö p-8 ΓåÆ p-6, banner rounded-full ΓåÆ rounded-2xl */}
          <div className="bg-white rounded-3xl border border-border p-6 shadow-sm">
            <h2 className="text-xs font-semibold text-muted-foreground uppercase tracking-widest mb-5">RISK ANALYSIS</h2>

            <div className="flex items-center justify-between mb-5">
              <span className="text-sm font-semibold text-foreground">Risk Level</span>
              <span className={`px-4 py-1 rounded-lg text-sm font-bold ${riskLevel === "Low" ? "bg-[#48BB78] text-white" : "bg-red-500 text-white"}`}>
                {riskLevel}
              </span>
            </div>

            {/* FIX: was rounded-full (pill), Figma shows rounded-2xl banner */}
            <div className={`rounded-2xl px-5 py-3.5 flex items-center gap-3 mb-7 ${
              riskLevel === "High"
                ? "bg-red-50 text-red-500 border border-red-100"
                : "bg-[#F0FFF4] text-[#48BB78] border border-[#C6F6D5]"
            }`}>
              {riskLevel === "High"
                ? <XCircle className="w-5 h-5 shrink-0" />
                : <CheckCircle2 className="w-5 h-5 shrink-0" />
              }
              <span className="text-sm font-semibold">
                {riskLevel === "High" ? "Bank name mismatch" : "The account details match"}
              </span>
            </div>

            <h3 className="text-xs font-semibold text-muted-foreground uppercase tracking-widest mb-4">CHECK PASSED</h3>
            <div className="space-y-4">
              <div className="flex items-center gap-3">
                {riskLevel === "High"
                  ? <XCircle className="w-5 h-5 text-destructive shrink-0" />
                  : <CheckCircle2 className="w-5 h-5 text-emerald-500 shrink-0" />
                }
                <span className="text-sm font-semibold text-foreground">
                  Bank account {riskLevel === "High" ? "unverified" : "verified"}
                </span>
                {riskLevel === "High" && (
                  <span className="px-2 py-0.5 rounded-md bg-gray-100 border border-gray-200 text-[10px] font-semibold text-gray-600">
                    Holder: {vendor.contactFirstName} {vendor.contactLastName}
                  </span>
                )}
              </div>
              <div className="flex items-center gap-3">
                <CheckCircle2 className="w-5 h-5 text-emerald-500 shrink-0" />
                <span className="text-sm font-semibold text-foreground">Business registration confirmed</span>
              </div>
            </div>
          </div>

          {/* Vendor Note */}
          {((isUnderReview || isRejected || isApprovedPhase4 || isActive || isDeactivated) && vendor.decisionNote) && (
            <div className="bg-primary/5 rounded-3xl border border-primary/20 p-6 shadow-sm">
              <h2 className="text-xs font-semibold text-muted-foreground uppercase tracking-widest mb-4">VENDOR NOTE</h2>
              <p className="text-sm text-foreground leading-relaxed font-semibold">{vendor.decisionNote}</p>
            </div>
          )}

          {/* Recent Transactions ΓÇö p-8 ΓåÆ p-6; "View all" ΓåÆ filled teal button */}
          {(isActive || isDeactivated) && !isApprovedPhase4 && (
            <div className="bg-white rounded-3xl border border-border p-6 shadow-sm">
              <div className="flex items-center justify-between mb-5">
                <h2 className="text-xs font-semibold text-muted-foreground uppercase tracking-widest">RECENT TRANSACTIONS</h2>
                <button
                  onClick={() => router.push(`/vendors/${vendorId}/transactions`)}
                  className="px-4 h-9 rounded-xl bg-primary text-primary-foreground text-sm font-bold hover:opacity-90 transition-opacity"
                >
                  View all
                </button>
              </div>
              <div className="divide-y divide-gray-100">
                {[1, 2, 3, 4, 5, 6].map((i) => (
                  <div key={i} className="flex items-center justify-between py-4">
                    <div className="flex items-center gap-3">
                      <div className="w-10 h-10 rounded-xl bg-gray-50 flex items-center justify-center shrink-0 border border-gray-100">
                        <FileText className="w-5 h-5 text-gray-300" />
                      </div>
                      <div>
                        <p className="text-sm font-semibold text-foreground">In-234-53</p>
                        <p className="text-xs font-medium text-muted-foreground">Jan 31, 2026</p>
                      </div>
                    </div>
                    <span className="text-sm font-bold text-primary">NGN 200,000.0</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* ΓöÇΓöÇ Request Info Modal ΓöÇΓöÇ */}
      {requestInfoModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/30 p-4 animate-in fade-in">
          <div className="bg-white rounded-3xl shadow-xl w-full max-w-md p-6 relative">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-xl font-bold text-gray-900">Request Info</h2>
              <button onClick={() => setRequestInfoModalOpen(false)}
                className="w-8 h-8 rounded-full bg-gray-100 hover:bg-gray-200 flex items-center justify-center transition-colors">
                <X className="w-4 h-4 text-gray-500" />
              </button>
            </div>
            <div className="mb-6">
              <label className="block text-sm font-semibold text-gray-700 mb-2">Message</label>
              <textarea value={infoMessage} onChange={(e) => setInfoMessage(e.target.value)}
                placeholder="Enter message here..." rows={5}
                className="w-full p-4 rounded-xl border border-gray-200 text-sm placeholder:text-gray-400 focus:outline-none focus:border-[#00BFA5] focus:ring-1 focus:ring-[#00BFA5] resize-none" />
            </div>
            <div className="flex flex-col sm:flex-row gap-3">
              <button onClick={() => setRequestInfoModalOpen(false)}
                className="flex-1 h-12 rounded-xl border border-gray-200 text-gray-600 font-semibold text-sm hover:bg-gray-50 transition-colors">
                Cancel
              </button>
              <button onClick={handleRequestInfo} disabled={!infoMessage.trim()}
                className="flex-1 h-12 rounded-xl bg-[#00BFA5] text-white font-semibold text-sm hover:opacity-90 transition-opacity disabled:opacity-50">
                Send message
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ΓöÇΓöÇ Reject Vendor Modal ΓöÇΓöÇ */}
      {rejectModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/30 p-4 animate-in fade-in">
          <div className="bg-white rounded-3xl shadow-xl w-full max-w-md p-6 relative">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-xl font-bold text-gray-900">Reject Vendor</h2>
              <button onClick={() => setRejectModalOpen(false)}
                className="w-8 h-8 rounded-full bg-gray-100 hover:bg-gray-200 flex items-center justify-center transition-colors">
                <X className="w-4 h-4 text-gray-500" />
              </button>
            </div>
            <div className="mb-6">
              <label className="block text-sm font-semibold text-gray-700 mb-2">Reason for Rejection</label>
              <textarea value={rejectReason} onChange={(e) => setRejectReason(e.target.value)}
                placeholder="e.g. Bank name mismatch, invalid tax ID, etc." rows={5}
                className="w-full p-4 rounded-xl border border-gray-200 text-sm placeholder:text-gray-400 focus:outline-none focus:border-red-500 focus:ring-1 focus:ring-red-500 resize-none" />
              <p className="text-xs text-gray-500 mt-2">This note will be sent to the vendor.</p>
            </div>
            <div className="flex flex-col sm:flex-row gap-3">
              <button onClick={() => setRejectModalOpen(false)}
                className="flex-1 h-12 rounded-xl border border-gray-200 text-gray-600 font-semibold text-sm hover:bg-gray-50 transition-colors">
                Cancel
              </button>
              <button onClick={() => handleDecision("rejected", rejectReason)}
                disabled={!rejectReason.trim() || isSubmitting}
                className="flex-1 h-12 rounded-xl bg-red-500 text-white font-semibold text-sm hover:bg-red-600 transition-colors disabled:opacity-50">
                {isSubmitting ? "Processing..." : "Reject Vendor"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

