"use client";

import { logger } from "@/lib/logger";

import { Button } from "@/components/ui/button";
import { ArrowRight, Loader2, Briefcase, Globe, Phone, Link as LinkIcon } from "lucide-react";
import { useRouter } from "next/navigation";
import {
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
  Form,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import z from "zod";
import { zodResolver } from "@hookform/resolvers/zod";
import { useForm } from "react-hook-form";
import OnboardingTitle from "@/components/onboarding/_shared/OnboardingTitle";
import { useOnboardingStore } from "@/stores/useVilletoStore";
import { Building03FreeIcons } from "@hugeicons/core-free-icons";

import { HugeiconsIcon } from "@hugeicons/react";
import { toast } from "sonner";
import { useUpdateOnboardingCompanyDetailsApi } from "@/queries/onboarding/update-onboarding-company-details";
import FormFieldSelect from "@/components/form fields/formFieldSelect";
import FormFieldInput from "@/components/form fields/formFieldInput";
import FormFieldLogoUpload from "@/components/form fields/formFieldLogoUpload";
import { useEffect, useRef } from "react";
import { onboardingBusinessSchema } from "@/lib/schemas/schemas";
import { useHydrateOnboardingData } from "@/hooks/useHydrateOnboardingData";

/** Map from 3-letter country code ΓåÆ dial prefix */
const COUNTRY_DIAL_CODES: Record<string, string> = {
  NGA: "+234",
  GHA: "+233",
  KEN: "+254",
  ZAF: "+27",
};

/** Strip known dial-code prefixes from a phone string */
function stripDialCode(phone: string): string {
  const allCodes = Object.values(COUNTRY_DIAL_CODES).sort(
    (a, b) => b.length - a.length // longest first to avoid partial matches
  );
  for (const code of allCodes) {
    if (phone.startsWith(code)) {
      return phone.slice(code.length).trimStart();
    }
  }
  return phone;
}

export default function Business() {
  const router = useRouter();
  const { businessSnapshot, updateBusinessSnapshot, _preOnboarding } =
    useOnboardingStore();
  useHydrateOnboardingData();
  const updateOnboarding = useUpdateOnboardingCompanyDetailsApi();

  const loading = updateOnboarding.isPending;

  const form = useForm({
    resolver: zodResolver(onboardingBusinessSchema),
    mode: "onChange",
    defaultValues: {
      business_name: "",
      contactPhone: businessSnapshot.contactNumber || "",
      countryOfRegistration: businessSnapshot.countryOfRegistration || "",
      websiteUrl: businessSnapshot.website || "",
      businessLogo: businessSnapshot.logo || undefined,
    },
  });

  useEffect(() => {
    // Filter out auto-generated business names (e.g. "user@email.com Group")
    const isAutoGenerated = businessSnapshot.businessName?.includes("@");
    form.reset({
      business_name: isAutoGenerated ? "" : (businessSnapshot.businessName || ""),
      contactPhone: businessSnapshot.contactNumber || "",
      countryOfRegistration: businessSnapshot.countryOfRegistration || "",
      websiteUrl: businessSnapshot.website || "",
      businessLogo: businessSnapshot.logo || undefined,
    });
  }, [businessSnapshot, form]);

  // Track whether this is the first render so we don't override a pre-filled phone
  const isFirstCountryChange = useRef(true);
  const watchedCountry = form.watch("countryOfRegistration");

  useEffect(() => {
    // Country cleared ΓÇö strip the dial code, keep only local digits
    if (!watchedCountry) {
      isFirstCountryChange.current = true; // reset so next selection behaves like first
      const current = form.getValues("contactPhone") || "";
      const localNumber = stripDialCode(current);
      form.setValue("contactPhone", localNumber, { shouldValidate: true });
      return;
    }

    const dialCode = COUNTRY_DIAL_CODES[watchedCountry];
    if (!dialCode) return;

    if (isFirstCountryChange.current) {
      // On first load: only prefix if the field is blank
      isFirstCountryChange.current = false;
      const current = form.getValues("contactPhone") || "";
      if (!current) {
        form.setValue("contactPhone", dialCode + " ", { shouldDirty: false });
      }
      return;
    }

    // On subsequent country changes: swap out the old prefix, keep digits
    const current = form.getValues("contactPhone") || "";
    const localNumber = stripDialCode(current);
    form.setValue("contactPhone", dialCode + (localNumber ? " " + localNumber : " "), {
      shouldValidate: true,
    });
  }, [watchedCountry, form]);

    async function onSubmit(data: z.infer<typeof onboardingBusinessSchema>) {
    try {
      const payload = {
        ...data,
        companyName: data.business_name,
      };
      const response = await updateOnboarding.mutateAsync(payload);

      // Convert logo file to base64 for local storage if it's a File
      // The API action handles conversion for API submission
      let logoUrl: string | undefined = undefined;
      if (data.businessLogo instanceof File) {
        logoUrl = await new Promise<string>((resolve, reject) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          reader.onerror = reject;
          reader.readAsDataURL(data.businessLogo as File);
        });
      } else if (typeof data.businessLogo === "string") {
        logoUrl = data.businessLogo;
      } else if (response?.data?.logo) {
        // Use logo from API response if available
        logoUrl = response.data.logo as string;
      }

      // Update the store with form data
      updateBusinessSnapshot({
        businessName: data.business_name,
        contactNumber: data.contactPhone,
        countryOfRegistration: data.countryOfRegistration,
        website: data.websiteUrl,
        logo: logoUrl, // Save logo to businessSnapshot
      });

      router.push("/onboarding/leadership");

    } catch (e: unknown) {
      logger.warn(e);
      const error = e as { response?: { data?: { message?: string } } };
      toast.error(
        error.response?.data?.message || "Failed to update company details"
      );
    }
  }

  return (
    <div className="space-y-8 flex flex-col justify-start h-full py-4">
      <div className="text-left ">
        <div className="w-16 h-16 bg-primary-light rounded-full flex mb-10">
          <HugeiconsIcon
            icon={Building03FreeIcons}
            className="size-16 text-primary"
          />
        </div>

        <OnboardingTitle
          title="Tell us more about your Business"
          subtitle="
                    Tell us about your business"
        />
      </div>
      <Form {...form}>
        <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 mt-4">
          <FormFieldLogoUpload
            control={form.control}
            name="businessLogo"
            label="Business Logo"
            description=""
            maxSize={1 * 1024 * 1024}
            variant="button"
          />

          <FormField
            control={form.control}
            name="business_name"
            render={({ field }) => (
              <FormItem>
                <FormLabel>Business Name<span className="text-destructive">*</span></FormLabel>
                <FormControl>
                    <div className="relative">
                        <div className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400">
                            <Briefcase className="h-5 w-5" />
                        </div>
                        <Input
                            {...field}
                            placeholder="Enter your business name"
                             className="pl-10 text-gray-600 bg-gray-50 border-gray-200"
                        />
                    </div>
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormFieldSelect
            control={form.control}
            name="countryOfRegistration"
            label="Country of Registration"
            values={[
              { label: "Nigeria", value: "NGA" },
              { label: "Ghana", value: "GHA" },
              { label: "Kenya", value: "KEN" },
              { label: "South Africa", value: "ZAF" },
            ]}
            placeholder="Select Country"
            prefixIcon={<Globe className="h-5 w-5 text-gray-400" />}
          />

          <FormFieldInput
            control={form.control}
            name="contactPhone"
            label="Contact Number"
            placeholder="+1"
            prefixIcon={<Phone className="h-5 w-5 text-gray-400" />}
          />

          <FormFieldInput
            control={form.control}
            name="websiteUrl"
            label="Website"
            placeholder="Enter your website link"
            type="text"
            prefixIcon={<LinkIcon className="h-5 w-5 text-gray-400" />}
          />

          {/* <FormField control={form.control} name="password"
                    render={({ field }) => (
                        <FormItem>
                            <FormLabel>Password</FormLabel>
                            <FormControl>

                                <Input type="password" {...field} />
                            </FormControl>
                            <FormMessage />
                        </FormItem>
                    )} />

                <div className="grid grid-cols-2 gap-3">

                    <FormField control={form.control} name="currency"
                        render={({ field }) => (
                            <FormItem>
                                <FormLabel>Currency</FormLabel>
                                <Select onValueChange={field.onChange} defaultValue={field.value} >
                                    <FormControl>
                                        <SelectTrigger>
                                            <SelectValue placeholder="Select a country" />
                                        </SelectTrigger>
                                    </FormControl>           <SelectContent>

                                        <SelectItem value="USD">USD</SelectItem>
                                        <SelectItem value="NGN">NGN</SelectItem>
                                    </SelectContent>
                                </Select>
                                <FormMessage />
                            </FormItem>
                        )} />
                </div> */}

          <div className="w-full flex mt-10">
            <Button
              type="submit"
              className="ml-auto! min-w-[250px] max-w-[250px] self-end"
              disabled={loading}
            >
              {loading ? "Creating..." : "Continue"}{" "}
              {loading ? (
                <Loader2 className="h-4 w-4 animate-spin" />
              ) : (
                <ArrowRight className="h-4 w-4" />
              )}
            </Button>
          </div>
        </form>
      </Form>
    </div>
  );
}

"use client"
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Plus, Trash2, Info, ArrowRight } from "lucide-react";
import { useState } from "react";
import { useRouter } from "next/navigation";
import { AddBeneficialOwnerModal } from "@/components/onboarding/AddBeneficialOwner";
import OnboardingTitle from "@/components/onboarding/_shared/OnboardingTitle";
import { useOnboardingStore } from "@/stores/useVilletoStore";
import { LeaderShipPayload, useUpdateOnboardingLeadersApi } from "@/queries/onboarding/update-leadership";
import { toast } from "sonner";
import { HugeiconsIcon } from "@hugeicons/react";
import { PencilEdit02FreeIcons, UserGroup03FreeIcons } from "@hugeicons/core-free-icons";
import { useHydrateOnboardingData } from "@/hooks/useHydrateOnboardingData";

interface Person {
    id: string;
    firstName: string;
    lastName: string;
    role: string;
    email: string;
    ownershipPercentage?: number;
    avatar?: string;
    phone?: string; // Add this
}

interface BeneficialOwner extends Person {
    ownershipPercentage: number;
}

interface Officer extends Person {
    role: string;
}

interface ComplianceNoticeProps {
    title: string;
    description: string;
}

export function ComplianceNotice({ title, description }: ComplianceNoticeProps) {
    return (
        <Card className="bg-primary/15 border-primary p-5">
            <div className="flex items-start gap-3.5">
                <Info className="h-5 w-5 text-primary flex-shrink-0" />
                <div>
                    <p className="text-base font-semibold leading-[100%] tracking-[0%] text-black mb-2">{title}</p>
                    <p className="text-xs font-normal leading-[100%] tracking-[0%] text-black">{description}</p>
                </div>
            </div>
        </Card>
    );
}

interface EmptyStateProps {
    imageSrc: string;
    imageAlt: string;
    message: string;
}

export function EmptyState({ imageSrc, imageAlt, message }: EmptyStateProps) {
    return (
        <div className="text-center space-y-10">
            <div className="flex justify-center">
                <img src={imageSrc} alt={imageAlt} className="w-48 h-48" />
            </div>
            <p className="text-muted-foreground text-base tracking-[0%] leading-[100%]">{message}</p>
        </div>
    );
}

interface OwnerCardProps {
    owner: {
        id: string;
        firstName: string;
        lastName: string;
        role: string;
        email: string;
        ownershipPercentage?: number;
        position?: string;
    };
    onEdit: (id: string) => void;
    onDelete: (id: string) => void;
    type: "beneficial" | "officer";
    showIcons: boolean
}

export function OwnerCard({ owner, onEdit, onDelete, type, showIcons = true }: OwnerCardProps) {
    return (
        <Card className="p-4">
            <div className="flex items-center justify-between gap-5">
                <div className="flex items-center gap-4 flex-1">
                    {/* Avatar */}
                    <div className="w-10 h-10 bg-gradient-to-br from-purple-500 to-orange-500 rounded-full flex items-center justify-center">
                        <span className="text-white font-semibold text-lg">
                            {owner.firstName.split('')[0] + owner.lastName.split('')[0]}
                        </span>
                    </div>

                    {/* Owner Info */}
                    <div className="flex-1">
                        <div className="flex items-center gap-3 mb-1">
                            <span className="font-semibold font-base">{owner.firstName} {owner.lastName}</span>
                            <span className="text-sm">
                                {type === "beneficial" ? owner.role : owner.position}
                            </span>
                            {type === "beneficial" && (
                                <span className="text-sm flex-auto">
                                    {owner.ownershipPercentage}%
                                </span>
                            )}
                        </div>

                    </div>
                </div>

                {/* Actions */}
                {showIcons && (<div className="flex items-center gap-2 shrink-0">
                    <Button variant="ghost" size="sm" onClick={() => onEdit(owner.id)}>
                        <HugeiconsIcon icon={PencilEdit02FreeIcons} className="h-4 w-4" />
                    </Button>
                    <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => onDelete(owner.id)}
                    >
                        <Trash2 className="h-4 w-4 text-destructive" />
                    </Button>
                </div>)}
            </div>
        </Card>
    );
}

interface ActionButtonsProps {
    onAdd: () => void;
    onContinue: () => void;
    hasOwners: boolean;
    loading: boolean;
    addButtonText: string;
    continueButtonText: string;
    layout?: "default" | "equal";
}

export function ActionButtons({
    onAdd,
    onContinue,
    hasOwners,
    addButtonText,
    continueButtonText,
    loading,
    layout = "default"
}: ActionButtonsProps) {
    if (layout === "equal") {
        return (
            <div className="flex items-center pt-8 w-full gap-4 mt-auto">
                <Button
                    variant="outline"
                    onClick={onAdd}
                    className="flex items-center gap-2 flex-1"
                    disabled={loading}
                >
                    {addButtonText}
                    <Plus className="h-4 w-4" />
                </Button>

                <Button
                    onClick={onContinue}
                    className={`flex items-center gap-2 flex-1 ${!hasOwners ? 'opacity-50' : ''}`}
                    disabled={!loading && !hasOwners}
                >
                    {hasOwners ? continueButtonText : "Next Step"}
                    <ArrowRight className="h-4 w-4" />
                </Button>
            </div>
        );
    }

    // If no owners, show single Add button at the bottom right with primary styling
    if (!hasOwners) {
        return (
            <div className="flex justify-end pt-8 mt-auto w-full">
                <Button
                    onClick={onAdd}
                    className="flex items-center gap-2"
                    disabled={loading}
                >
                    {addButtonText} <Plus className="h-4 w-4" />
                </Button>
            </div>
        );
    }

    return (
        <div className="flex justify-between items-center pt-8 mt-auto gap-5 w-full">
            <Button
                variant="outline"
                onClick={onAdd}
                className="flex items-center gap-2 flex-1"
                disabled={loading}
            >
                {addButtonText}
                <Plus className="h-4 w-4" />
            </Button>

            <Button
                onClick={onContinue}
                className="flex items-center gap-2 flex-1"
                disabled={loading}
            >
                {continueButtonText}
                <ArrowRight className="h-4 w-4" />
            </Button>
        </div>
    );
}

export default function Leadership() {
    const router = useRouter();
    const { userProfiles, updateUserProfiles } = useOnboardingStore();
    useHydrateOnboardingData();
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [selectedTab, _setSelectedTab] = useState<"beneficial" | "officer">("beneficial");
    const [editingPerson, setEditingPerson] = useState<{ id: string; type: "beneficial" | "officer" } | null>(null);

    // Filter only beneficial owners (though we might clear others if they exist from before)
    const beneficialOwners = userProfiles.filter(profile => profile.ownershipPercentage !== undefined) as BeneficialOwner[];

    const updateOnboarding = useUpdateOnboardingLeadersApi()
    const loading = updateOnboarding.isPending;

    const handleAddPerson = (person: Omit<BeneficialOwner, "id"> | Omit<Officer, "id">) => {
        if (editingPerson) {
            // Editing existing person
            const updatedProfiles = userProfiles.map(p =>
                p.id === editingPerson.id
                    ? { ...p, ...person, avatar: `${person.firstName.split(' ')[0] + person.lastName.split(' ')[0]}` }
                    : p
            );
            updateUserProfiles(updatedProfiles);
        } else {
            // Adding new person
            const newPerson = {
                ...person,
                id: Date.now().toString(),
                avatar: `${person.firstName.split(' ')[0] + person.lastName.split(' ')[0]}`,
            };
            const updatedProfiles = [...userProfiles, newPerson];
            updateUserProfiles(updatedProfiles);
        }

        setIsModalOpen(false);
        setEditingPerson(null);
    };

    const handleEditPerson = (id: string) => {
        const person = userProfiles.find(p => p.id === id);
        if (person) {
            setEditingPerson({ id, type: "beneficial" });
            setIsModalOpen(true);
        }
    };

    const handleDeletePerson = (id: string) => {
        const updatedProfiles = userProfiles.filter(profile => profile.id !== id);
        updateUserProfiles(updatedProfiles);
    };

    // Transform the data to match the payload format
    const transformDataForPayload = () => {
        const payload: LeaderShipPayload = {
            businessOwners: beneficialOwners.map(owner => ({
                firstName: owner.firstName,
                lastName: owner.lastName,
                email: owner.email,
                // Add default or make phone required in your interface
                ownershipPercentage: owner.ownershipPercentage || 0,

            })),
            // officers: [] // Removed officers from payload as requested
        };
        return payload;
    };

    const handleContinue = async () => {
        try {
            const payload = transformDataForPayload();

            // Submit the data
            const _response = await updateOnboarding.mutateAsync(payload);
            toast.success("Leader details updated successfully!");
            router.push("/onboarding/financial");
        } catch (error) {
            toast.error(error instanceof Error ? error.message : "Failed to update company details");
        }
    };


    const hasOwners = beneficialOwners.length > 0;

    return (
        <div className="h-full flex-col flex">
            <div className="text-left space-y-4">
                <div className=" size-24 flex items-center justify-center bg-primary-light rounded-full mb-10">
                    <HugeiconsIcon icon={UserGroup03FreeIcons} className="size-16 text-primary" />

                </div>

                <OnboardingTitle
                    title="Beneficial Owner"
                    subtitle="Enter details of owner(s) of the company."
                />
            </div>

            <div className="mt-7 h-full flex-col flex">
                <ComplianceNotice
                    title="No Single Owner holds 25% or more"
                    description="We ask for this to stay compliant with financial regulations"
                />

                {!hasOwners ? (
                    <EmptyState
                        imageSrc="/images/leadership.png"
                        imageAlt="Add beneficial owners"
                        message={"No beneficial owner has been added yet, click button below to add."}
                    />
                ) : (
                    <div className="space-y-4 mt-5">
                        {beneficialOwners.map((person) => (
                            <OwnerCard
                                key={person.id}
                                owner={person}
                                onEdit={handleEditPerson}
                                onDelete={handleDeletePerson}
                                type="beneficial"
                                showIcons
                            />
                        ))}
                    </div>
                )}

                <ActionButtons
                    onAdd={() => setIsModalOpen(true)}
                    onContinue={handleContinue}
                    hasOwners={hasOwners}
                    addButtonText="Add Beneficial Owner"
                    continueButtonText="Next Step" // "Next Step" even if owners exist, as requested
                    layout="default"
                    loading={loading}
                />

                <AddBeneficialOwnerModal
                    isOpen={isModalOpen}
                    onClose={() => {
                        setIsModalOpen(false);
                        setEditingPerson(null);
                    }}
                    onAdd={handleAddPerson}
                    mode="beneficial"
                    isOwner={true}
                    editingPerson={editingPerson ? userProfiles.find(p => p.id === editingPerson.id) : undefined}
                />
            </div>
        </div>
    );
}

